const _astro_dataLayerContent = [["Map",1,2,9,10,307,308],"meta::meta",["Map",3,4,5,6,7,8],"astro-config-digest","{\"root\":{},\"srcDir\":{},\"publicDir\":{},\"outDir\":{},\"cacheDir\":{},\"compressHTML\":true,\"base\":\"/\",\"trailingSlash\":\"ignore\",\"output\":\"server\",\"scopedStyleStrategy\":\"attribute\",\"build\":{\"format\":\"directory\",\"client\":{},\"server\":{},\"assets\":\"_astro\",\"serverEntry\":\"entry.mjs\",\"redirects\":false,\"inlineStylesheets\":\"auto\",\"concurrency\":1},\"server\":{\"open\":false,\"host\":false,\"port\":4321,\"allowedHosts\":[]},\"redirects\":{},\"image\":{\"endpoint\":{\"route\":\"/_image\"},\"service\":{\"entrypoint\":\"astro/assets/services/sharp\",\"config\":{}},\"dangerouslyProcessSVG\":false,\"domains\":[],\"remotePatterns\":[],\"responsiveStyles\":false},\"devToolbar\":{\"enabled\":true},\"markdown\":{\"syntaxHighlight\":{\"type\":\"shiki\",\"excludeLangs\":[\"math\"]},\"shikiConfig\":{\"langs\":[],\"langAlias\":{},\"theme\":\"github-dark\",\"themes\":{},\"wrap\":false,\"transformers\":[]},\"remarkPlugins\":[],\"rehypePlugins\":[],\"remarkRehype\":{},\"gfm\":true,\"smartypants\":{\"backticks\":true,\"closingQuotes\":{\"double\":\"”\",\"single\":\"’\"},\"dashes\":true,\"ellipses\":true,\"openingQuotes\":{\"double\":\"“\",\"single\":\"‘\"},\"quotes\":true}},\"i18n\":{\"defaultLocale\":\"en\",\"locales\":[\"en\",\"es\"],\"routing\":{\"prefixDefaultLocale\":false,\"redirectToDefaultLocale\":false,\"fallbackType\":\"redirect\"}},\"security\":{\"checkOrigin\":true,\"allowedDomains\":[],\"csp\":false,\"actionBodySizeLimit\":1048576,\"serverIslandBodySizeLimit\":1048576},\"env\":{\"schema\":{},\"validateSecrets\":false},\"prerenderConflictBehavior\":\"warn\",\"experimental\":{\"advancedRouting\":false,\"clientPrerender\":false,\"contentIntellisense\":false,\"chromeDevtoolsWorkspace\":false,\"rustCompiler\":false,\"queuedRendering\":{\"enabled\":false}},\"legacy\":{\"collectionsBackwardsCompat\":false}}","astro-version","6.3.3","content-config-digest","399c67953d1a6a4c","proyectos",["Map",11,12,63,64,101,102,135,136,170,171,205,206,239,240,275,276],"capfa",{id:11,data:13,body:29,filePath:30,digest:31,rendered:32},{title:14,description:15,publishDate:16,tags:17,img:21,img_alt:22,screenshots:23},"CAPFA Constructora actualización de sitio.","CAPFA Constructora buscaba una transformación digital integral para mejorar el rendimiento, SEO y la experiencia de usuario. Su sitio anterior, con un puntaje de rendimiento de 45%, se sentía anticuado y carecía de interacción efectiva con el usuario.\n",["Date","2019-12-01T00:00:00.000Z"],[18,19,20],"Dev","Branding","Frontend","/assets/capfaArticleImg.webp","Screenshot of CAPFA Website Revamp",[24,25,26,27,28],"/assets/capfa/1.png","/assets/capfa/2.png","/assets/capfa/3.png","/assets/capfa/4.png","/assets/capfa/5.png","### Descripción del Proyecto\n\nNuestros objetivos eran mejorar la velocidad, optimizar el SEO, modernizar la UX/UI y aplicar una estructura basada en componentes para una mayor calidad y mantenimiento del software.\n\n#### Objetivos\n- **Rendimiento y Accesibilidad**: Elevar los puntajes de Google Lighthouse.\n- **Usabilidad e Interacción**: Rediseñar la UX/UI para reflejar la identidad de CAPFA.\n- **Facilidad de Actualización**: Permitir que CAPFA actualice el sitio regularmente mediante WordPress y DIVI.\n- **Presencia Digital**: Aumentar la interacción a través de la integración de redes sociales y un diseño centrado en el usuario.\n\n#### Flujo de Trabajo del Proyecto\n**Descubrimiento y Planificación**: Establecimos la identidad de marca de CAPFA con una paleta de colores personalizada, tipografía y wireframes para aumentar la interacción.\n\n#### Diseño y Desarrollo\n- **Estructuración de Páginas**: Desarrollamos plantillas para secciones como \"Contacto\", \"Nosotros\" y \"Proyectos\".\n- **SEO y Accesibilidad**: Usamos herramientas nativas de DIVI para una SEO y accesibilidad optimizados.\n- **Estructura Basada en Componentes**: Incorporamos funciones PHP personalizadas y herramientas modulares de DIVI para mejorar la gestión del backend.\n- **Funcionalidades Dinámicas**: Implementamos un botón de WhatsApp interactivo con JavaScript, evitando plugins que afecten el rendimiento.\n- **Pruebas y Optimización**: Logramos una puntuación del 94% en Google Lighthouse y validamos con Google Analytics y otras herramientas de pruebas.\n- **Cronograma de Ejecución**: Seguimos una planificación semanal estructurada para asegurar la finalización del proyecto a tiempo.\n\n#### Tecnologías Utilizadas\n- **WordPress**: Para facilitar las actualizaciones del cliente.\n- **DIVI**: Por su modularidad y capacidades de SEO.\n- **PHP, JavaScript, HTML, CSS**: Aplicados para funcionalidades personalizadas, estilos y optimización de interactividad sin cargar plugins adicionales.\n\n#### Resultados e Impacto\n\n- **Rendimiento**: Mejoramos la puntuación de Lighthouse del 45% al 94%, logrando tiempos de carga más rápidos y una mayor retención de usuarios.\n- **Usabilidad e Interacción**: Mejoramos la interacción y accesibilidad, facilitando la conexión entre las redes sociales y el sitio web de CAPFA.\n- **Empoderamiento del Cliente**: CAPFA ahora gestiona actualizaciones de contenido de forma independiente, fortaleciendo su presencia digital y estrategia de interacción.","src/content/proyectos/CAPFA.md","869b8a7a3afeb8e4",{html:33,metadata:34},"<h3 id=\"descripción-del-proyecto\">Descripción del Proyecto</h3>\n<p>Nuestros objetivos eran mejorar la velocidad, optimizar el SEO, modernizar la UX/UI y aplicar una estructura basada en componentes para una mayor calidad y mantenimiento del software.</p>\n<h4 id=\"objetivos\">Objetivos</h4>\n<ul>\n<li><strong>Rendimiento y Accesibilidad</strong>: Elevar los puntajes de Google Lighthouse.</li>\n<li><strong>Usabilidad e Interacción</strong>: Rediseñar la UX/UI para reflejar la identidad de CAPFA.</li>\n<li><strong>Facilidad de Actualización</strong>: Permitir que CAPFA actualice el sitio regularmente mediante WordPress y DIVI.</li>\n<li><strong>Presencia Digital</strong>: Aumentar la interacción a través de la integración de redes sociales y un diseño centrado en el usuario.</li>\n</ul>\n<h4 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h4>\n<p><strong>Descubrimiento y Planificación</strong>: Establecimos la identidad de marca de CAPFA con una paleta de colores personalizada, tipografía y wireframes para aumentar la interacción.</p>\n<h4 id=\"diseño-y-desarrollo\">Diseño y Desarrollo</h4>\n<ul>\n<li><strong>Estructuración de Páginas</strong>: Desarrollamos plantillas para secciones como “Contacto”, “Nosotros” y “Proyectos”.</li>\n<li><strong>SEO y Accesibilidad</strong>: Usamos herramientas nativas de DIVI para una SEO y accesibilidad optimizados.</li>\n<li><strong>Estructura Basada en Componentes</strong>: Incorporamos funciones PHP personalizadas y herramientas modulares de DIVI para mejorar la gestión del backend.</li>\n<li><strong>Funcionalidades Dinámicas</strong>: Implementamos un botón de WhatsApp interactivo con JavaScript, evitando plugins que afecten el rendimiento.</li>\n<li><strong>Pruebas y Optimización</strong>: Logramos una puntuación del 94% en Google Lighthouse y validamos con Google Analytics y otras herramientas de pruebas.</li>\n<li><strong>Cronograma de Ejecución</strong>: Seguimos una planificación semanal estructurada para asegurar la finalización del proyecto a tiempo.</li>\n</ul>\n<h4 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h4>\n<ul>\n<li><strong>WordPress</strong>: Para facilitar las actualizaciones del cliente.</li>\n<li><strong>DIVI</strong>: Por su modularidad y capacidades de SEO.</li>\n<li><strong>PHP, JavaScript, HTML, CSS</strong>: Aplicados para funcionalidades personalizadas, estilos y optimización de interactividad sin cargar plugins adicionales.</li>\n</ul>\n<h4 id=\"resultados-e-impacto\">Resultados e Impacto</h4>\n<ul>\n<li><strong>Rendimiento</strong>: Mejoramos la puntuación de Lighthouse del 45% al 94%, logrando tiempos de carga más rápidos y una mayor retención de usuarios.</li>\n<li><strong>Usabilidad e Interacción</strong>: Mejoramos la interacción y accesibilidad, facilitando la conexión entre las redes sociales y el sitio web de CAPFA.</li>\n<li><strong>Empoderamiento del Cliente</strong>: CAPFA ahora gestiona actualizaciones de contenido de forma independiente, fortaleciendo su presencia digital y estrategia de interacción.</li>\n</ul>",{headings:35,localImagePaths:56,remoteImagePaths:57,frontmatter:58,imagePaths:62},[36,40,44,47,50,53],{depth:37,slug:38,text:39},3,"descripción-del-proyecto","Descripción del Proyecto",{depth:41,slug:42,text:43},4,"objetivos","Objetivos",{depth:41,slug:45,text:46},"flujo-de-trabajo-del-proyecto","Flujo de Trabajo del Proyecto",{depth:41,slug:48,text:49},"diseño-y-desarrollo","Diseño y Desarrollo",{depth:41,slug:51,text:52},"tecnologías-utilizadas","Tecnologías Utilizadas",{depth:41,slug:54,text:55},"resultados-e-impacto","Resultados e Impacto",[],[],{title:14,publishDate:59,img:21,img_alt:22,description:15,tags:60,screenshots:61},["Date","2019-12-01T00:00:00.000Z"],[18,19,20],[24,25,26,27,28],[],"larry",{id:63,data:65,body:80,filePath:81,digest:82,rendered:83},{title:66,description:67,publishDate:68,tags:69,img:73,img_alt:74,screenshots:75},"Larry Props Sitio Web Interactivo de E-Commerce","El sitio web de Larry Props atiende un mercado de nicho en accesorios de mentalismo de alta calidad, ofreciendo herramientas profesionales diseñadas para artistas.\n",["Date","2019-02-02T00:00:00.000Z"],[70,71,20,72],"Diseño","Marca","Backend","/assets/Larry/1.webp","Captura de Pantalla del Sitio Web Larryprops.com",[76,77,78,79],"/assets/Larry/2.png","/assets/Larry/3.png","/assets/Larry/4.png","/assets/Larry/5.png","### Resumen del Proyecto  \n Como plataforma interactiva de e-commerce, prioriza la satisfacción del cliente, una marca premium y conversiones optimizadas a través de redes sociales. El diseño del sitio destaca la artesanía y la calidad, mientras que la funcionalidad apoya ventas directas y el compromiso del usuario.  \n\n#### Objetivos  \n- **Optimización de E-Commerce:** Desarrollar una tienda fácil de usar que enfatice la dedicación de Larry Props a la calidad y singularidad.  \n- **Embudo de Conversión:** Crear una landing page que convierta eficientemente a los visitantes de redes sociales en clientes.  \n- **SEO y Rendimiento:** Mejorar la visibilidad en búsquedas y reducir los tiempos de carga para una experiencia de usuario fluida.  \n- **Independencia del Cliente:** Empoderar a Larry Props para actualizar contenido y gestionar inventario con facilidad.  \n\n#### Flujo de Trabajo del Proyecto  \n- **Planificación:** Se estableció una identidad de marca distintiva centrada en la calidad y una navegación simplificada.  \n- **Diseño y Desarrollo:** Se diseñó una interfaz intuitiva con secciones esenciales como “Tienda”, “Acerca de” y “Contacto” para una experiencia sin inconvenientes.  \n- **Componentes Dinámicos:** Se utilizó el diseño modular de DIVI y código personalizado para presentar descripciones de productos, medios y testimonios de clientes.  \n- **Pruebas y Optimización:** Se llevaron a cabo evaluaciones de rendimiento, logrando tiempos de carga rápidos e interacciones fluidas para mejorar la experiencia del usuario.  \n\n#### Tecnologías Utilizadas  \n- **WordPress y DIVI:** Gestión de contenido flexible y personalización del diseño.  \n- **HTML/CSS/JavaScript Personalizados:** Funcionalidades interactivas optimizadas para e-commerce sin plugins pesados.  \n\n#### Resultados e Impacto  \n- **Aumento de Conversión:** La landing page optimizada llevó a una mayor participación de usuarios y aumentó las conversiones de ventas.  \n- **Crecimiento de Marca:** Mayor credibilidad y reconocimiento como proveedor premium en la comunidad de mentalismo.  \n- **Flexibilidad del Cliente:** Larry Props ahora gestiona fácilmente las listas de productos e inventario, apoyando una línea de productos dinámica y en evolución.","src/content/proyectos/Larry.md","78ab7b376709b102",{html:84,metadata:85},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>Como plataforma interactiva de e-commerce, prioriza la satisfacción del cliente, una marca premium y conversiones optimizadas a través de redes sociales. El diseño del sitio destaca la artesanía y la calidad, mientras que la funcionalidad apoya ventas directas y el compromiso del usuario.</p>\n<h4 id=\"objetivos\">Objetivos</h4>\n<ul>\n<li><strong>Optimización de E-Commerce:</strong> Desarrollar una tienda fácil de usar que enfatice la dedicación de Larry Props a la calidad y singularidad.</li>\n<li><strong>Embudo de Conversión:</strong> Crear una landing page que convierta eficientemente a los visitantes de redes sociales en clientes.</li>\n<li><strong>SEO y Rendimiento:</strong> Mejorar la visibilidad en búsquedas y reducir los tiempos de carga para una experiencia de usuario fluida.</li>\n<li><strong>Independencia del Cliente:</strong> Empoderar a Larry Props para actualizar contenido y gestionar inventario con facilidad.</li>\n</ul>\n<h4 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h4>\n<ul>\n<li><strong>Planificación:</strong> Se estableció una identidad de marca distintiva centrada en la calidad y una navegación simplificada.</li>\n<li><strong>Diseño y Desarrollo:</strong> Se diseñó una interfaz intuitiva con secciones esenciales como “Tienda”, “Acerca de” y “Contacto” para una experiencia sin inconvenientes.</li>\n<li><strong>Componentes Dinámicos:</strong> Se utilizó el diseño modular de DIVI y código personalizado para presentar descripciones de productos, medios y testimonios de clientes.</li>\n<li><strong>Pruebas y Optimización:</strong> Se llevaron a cabo evaluaciones de rendimiento, logrando tiempos de carga rápidos e interacciones fluidas para mejorar la experiencia del usuario.</li>\n</ul>\n<h4 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h4>\n<ul>\n<li><strong>WordPress y DIVI:</strong> Gestión de contenido flexible y personalización del diseño.</li>\n<li><strong>HTML/CSS/JavaScript Personalizados:</strong> Funcionalidades interactivas optimizadas para e-commerce sin plugins pesados.</li>\n</ul>\n<h4 id=\"resultados-e-impacto\">Resultados e Impacto</h4>\n<ul>\n<li><strong>Aumento de Conversión:</strong> La landing page optimizada llevó a una mayor participación de usuarios y aumentó las conversiones de ventas.</li>\n<li><strong>Crecimiento de Marca:</strong> Mayor credibilidad y reconocimiento como proveedor premium en la comunidad de mentalismo.</li>\n<li><strong>Flexibilidad del Cliente:</strong> Larry Props ahora gestiona fácilmente las listas de productos e inventario, apoyando una línea de productos dinámica y en evolución.</li>\n</ul>",{headings:86,localImagePaths:94,remoteImagePaths:95,frontmatter:96,imagePaths:100},[87,90,91,92,93],{depth:37,slug:88,text:89},"resumen-del-proyecto","Resumen del Proyecto",{depth:41,slug:42,text:43},{depth:41,slug:45,text:46},{depth:41,slug:51,text:52},{depth:41,slug:54,text:55},[],[],{title:66,publishDate:97,img:73,img_alt:74,description:67,tags:98,screenshots:99},["Date","2019-02-02T00:00:00.000Z"],[70,71,20,72],[76,77,78,79],[],"lena",{id:101,data:103,body:116,filePath:117,digest:118,rendered:119},{title:104,description:105,publishDate:106,tags:107,img:108,img_alt:109,screenshots:110},"Estudio Lena Sitio Web","El sitio web de Estudio Lena sirve como un recurso legal y un centro de contacto para casos de accidentes y lesiones, gestionado por un equipo de expertos legales.\n",["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],"/assets/Lena/1.webp","Screenshot del Sitio web de Lena estudio.",[111,112,113,114,115],"/assets/Lena/2.png","/assets/Lena/3.png","/assets/Lena/4.png","/assets/Lena/5.png","/assets/Lena/6.png","### **Resumen del Proyecto**\nEl sitio web de Estudio Lena actúa como un recurso legal y un centro de contacto para casos de accidentes y lesiones. Este sitio también funciona como una landing page para la conversión de usuarios, diseñada estratégicamente para canalizar tráfico desde redes sociales hacia una iniciación de “pre-caso” en línea, simplificando tanto la incorporación de clientes como la gestión de casos para el bufete de abogados.\n\n#### **Objetivos**\n- **Presencia Digital**: Reforzar la reputación de Estudio Lena en lesiones personales y derecho de accidentes.\n- **Embudo de Conversión de Usuarios**: Atraer tráfico impulsado por redes sociales y simplificar el proceso de ingreso de clientes a través de un formulario automatizado de “pre-caso”.\n- **Sistema de Gestión Eficiente**: Mejorar flujos de trabajo internos con una estructura de gestión de contenido personalizada para la colaboración del equipo.\n- **Accesibilidad y SEO**: Optimizar para la accesibilidad, asegurando un amplio alcance y fácil usabilidad.\n\n#### **Flujo de Trabajo del Proyecto**\n1. **Descubrimiento y Planificación**: Establecimiento de un mensaje de marca y diseño de una UX/UI centrada en el ámbito legal para inspirar confianza y profesionalismo.\n2. **Diseño UX/UI**: Estructuración del sitio con navegación clara a través de páginas como “Acerca de”, “Áreas de Práctica” y “Contacto”, enfatizando un diseño amigable para el usuario y una navegación fluida.\n3. **Estrategia de Contenido**: Organización del contenido en torno a los principales servicios legales, destacando áreas como “Accidentes” y “Consultas Gratuitas” para alinearse con la intención de búsqueda del usuario.\n4. **Formulario Automatizado de Pre-Caso**: Se añadió un formulario que permite a los usuarios iniciar casos en línea, reduciendo los tiempos de ingreso y mejorando el seguimiento de clientes para el equipo legal.\n5. **Pruebas y Optimización**: Realización de pruebas de usabilidad y rendimiento para verificar la velocidad del sitio, SEO y experiencia del usuario.\n\n#### **Tecnologías Utilizadas**\n- **WordPress**: Proporciona gestión de contenido fácil y seguimiento de datos en el backend para el equipo.\n- **DIVI Builder**: Permite un diseño modular y flexible adecuado para necesidades de contenido en evolución.\n- **HTML/CSS/JS Personalizados**: Funciones dinámicas adaptadas e interacciones de formulario optimizadas para una experiencia de usuario más fluida.\n\n#### **Resultados e Impacto**\n- **Mejora en la Tasa de Conversión**: El diseño de la landing page optimizada para redes sociales aumentó las consultas y conversiones de clientes.\n- **Flujo de Trabajo Mejorado**: El sistema automatizado de iniciación de “pre-caso” mejoró la eficiencia de ingreso y la colaboración del equipo.\n- **Autoridad de Marca**: Un sitio web profesional y funcional establece a Estudio Lena como un líder en el derecho de lesiones personales, brindando credibilidad y conveniencia.","src/content/proyectos/Lena.md","6f6cfc7b5057ff2d",{html:120,metadata:121},"<h3 id=\"resumen-del-proyecto\"><strong>Resumen del Proyecto</strong></h3>\n<p>El sitio web de Estudio Lena actúa como un recurso legal y un centro de contacto para casos de accidentes y lesiones. Este sitio también funciona como una landing page para la conversión de usuarios, diseñada estratégicamente para canalizar tráfico desde redes sociales hacia una iniciación de “pre-caso” en línea, simplificando tanto la incorporación de clientes como la gestión de casos para el bufete de abogados.</p>\n<h4 id=\"objetivos\"><strong>Objetivos</strong></h4>\n<ul>\n<li><strong>Presencia Digital</strong>: Reforzar la reputación de Estudio Lena en lesiones personales y derecho de accidentes.</li>\n<li><strong>Embudo de Conversión de Usuarios</strong>: Atraer tráfico impulsado por redes sociales y simplificar el proceso de ingreso de clientes a través de un formulario automatizado de “pre-caso”.</li>\n<li><strong>Sistema de Gestión Eficiente</strong>: Mejorar flujos de trabajo internos con una estructura de gestión de contenido personalizada para la colaboración del equipo.</li>\n<li><strong>Accesibilidad y SEO</strong>: Optimizar para la accesibilidad, asegurando un amplio alcance y fácil usabilidad.</li>\n</ul>\n<h4 id=\"flujo-de-trabajo-del-proyecto\"><strong>Flujo de Trabajo del Proyecto</strong></h4>\n<ol>\n<li><strong>Descubrimiento y Planificación</strong>: Establecimiento de un mensaje de marca y diseño de una UX/UI centrada en el ámbito legal para inspirar confianza y profesionalismo.</li>\n<li><strong>Diseño UX/UI</strong>: Estructuración del sitio con navegación clara a través de páginas como “Acerca de”, “Áreas de Práctica” y “Contacto”, enfatizando un diseño amigable para el usuario y una navegación fluida.</li>\n<li><strong>Estrategia de Contenido</strong>: Organización del contenido en torno a los principales servicios legales, destacando áreas como “Accidentes” y “Consultas Gratuitas” para alinearse con la intención de búsqueda del usuario.</li>\n<li><strong>Formulario Automatizado de Pre-Caso</strong>: Se añadió un formulario que permite a los usuarios iniciar casos en línea, reduciendo los tiempos de ingreso y mejorando el seguimiento de clientes para el equipo legal.</li>\n<li><strong>Pruebas y Optimización</strong>: Realización de pruebas de usabilidad y rendimiento para verificar la velocidad del sitio, SEO y experiencia del usuario.</li>\n</ol>\n<h4 id=\"tecnologías-utilizadas\"><strong>Tecnologías Utilizadas</strong></h4>\n<ul>\n<li><strong>WordPress</strong>: Proporciona gestión de contenido fácil y seguimiento de datos en el backend para el equipo.</li>\n<li><strong>DIVI Builder</strong>: Permite un diseño modular y flexible adecuado para necesidades de contenido en evolución.</li>\n<li><strong>HTML/CSS/JS Personalizados</strong>: Funciones dinámicas adaptadas e interacciones de formulario optimizadas para una experiencia de usuario más fluida.</li>\n</ul>\n<h4 id=\"resultados-e-impacto\"><strong>Resultados e Impacto</strong></h4>\n<ul>\n<li><strong>Mejora en la Tasa de Conversión</strong>: El diseño de la landing page optimizada para redes sociales aumentó las consultas y conversiones de clientes.</li>\n<li><strong>Flujo de Trabajo Mejorado</strong>: El sistema automatizado de iniciación de “pre-caso” mejoró la eficiencia de ingreso y la colaboración del equipo.</li>\n<li><strong>Autoridad de Marca</strong>: Un sitio web profesional y funcional establece a Estudio Lena como un líder en el derecho de lesiones personales, brindando credibilidad y conveniencia.</li>\n</ul>",{headings:122,localImagePaths:128,remoteImagePaths:129,frontmatter:130,imagePaths:134},[123,124,125,126,127],{depth:37,slug:88,text:89},{depth:41,slug:42,text:43},{depth:41,slug:45,text:46},{depth:41,slug:51,text:52},{depth:41,slug:54,text:55},[],[],{title:104,publishDate:131,img:108,img_alt:109,description:105,tags:132,screenshots:133},["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],[111,112,113,114,115],[],"michel",{id:135,data:137,body:150,filePath:151,digest:152,rendered:153},{title:138,description:139,publishDate:140,tags:141,img:143,img_alt:144,screenshots:145},"Michel Mentalista Sitio Web","¡Diseñado para funcionar como un portafolio y una Landing page enfocada en la conversión!\n",["Date","2020-03-02T00:00:00.000Z"],[20,18,142],"Marketing","/assets/michelWeb.webp","Screenshot de sitio web de Michel.",[146,147,148,149],"/assets/michel/1.png","/assets/michel/2.png","/assets/michel/3.png","/assets/michel/4.png","### Resumen del Proyecto\nEl sitio web de Michel Mentalista promociona a Michel, un destacado mentalista en Argentina, resaltando sus actuaciones en eventos privados, corporativos y de teatro. Diseñado para funcionar como un portafolio y una landing page centrada en la conversión, atrae audiencias a través de embudos de redes sociales para impulsar consultas y reservas.\n\n##### Objetivos\n- **Presencia Digital:** Elevar la marca de Michel con un sitio moderno y memorable.\n- **Compromiso del Usuario y Conversión:** Desarrollar una página altamente efectiva optimizada para el tráfico de redes sociales.\n- **Rendimiento y Accesibilidad:** Asegurar tiempos de carga rápidos y una interfaz accesible y amigable.\n- **Flexibilidad de Contenido:** Permitir actualizaciones fáciles en las secciones de “Shows” y “Galería” para mostrar eventos recientes.\n\n##### Flujo de Trabajo del Proyecto\n- **Descubrimiento y Planificación:** Definición de la marca con un enfoque interactivo y visualmente atractivo.\n- **Diseño UX/UI:** Desarrollo de un diseño claro con secciones como “Shows”, “Trailer”, “Bio” y “Contacto” para mejorar la navegación y el compromiso.\n- **Estrategia de Contenido:** Organización del contenido en torno a la experiencia y testimonios de Michel para generar credibilidad.\n- **Elementos Interactivos:** Adición de características atractivas como un “Trailer” y una “Galería” para aumentar la interacción en la página.\n- **Pruebas y Optimización:** Realización de pruebas de velocidad y usabilidad para garantizar una experiencia de usuario fluida y efectividad como landing page para el tráfico de redes sociales.\n\n##### Tecnologías Utilizadas\n- **WordPress:** Elegido para la gestión de contenido que permite actualizaciones sencillas.\n- **DIVI Builder:** Usado para un diseño modular personalizado que resalta servicios y testimonios.\n- **HTML/CSS/JS Personalizados:** Integración de elementos interactivos para mejorar la experiencia del usuario sin afectar los tiempos de carga.\n\n##### Resultados e Impacto\n- **Mayores Conversiones:** La landing page optimizada llevó a un aumento en el compromiso y las reservas.\n- **Identidad de Marca Mejorada:** El sitio profesional y atractivo establece a Michel como un mentalista líder.\n- **Empoderamiento del Cliente:** Michel ahora puede gestionar actualizaciones de forma independiente, mostrando consistentemente su trabajo más reciente.","src/content/proyectos/Michel.md","6a707718a594a2e6",{html:154,metadata:155},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>El sitio web de Michel Mentalista promociona a Michel, un destacado mentalista en Argentina, resaltando sus actuaciones en eventos privados, corporativos y de teatro. Diseñado para funcionar como un portafolio y una landing page centrada en la conversión, atrae audiencias a través de embudos de redes sociales para impulsar consultas y reservas.</p>\n<h5 id=\"objetivos\">Objetivos</h5>\n<ul>\n<li><strong>Presencia Digital:</strong> Elevar la marca de Michel con un sitio moderno y memorable.</li>\n<li><strong>Compromiso del Usuario y Conversión:</strong> Desarrollar una página altamente efectiva optimizada para el tráfico de redes sociales.</li>\n<li><strong>Rendimiento y Accesibilidad:</strong> Asegurar tiempos de carga rápidos y una interfaz accesible y amigable.</li>\n<li><strong>Flexibilidad de Contenido:</strong> Permitir actualizaciones fáciles en las secciones de “Shows” y “Galería” para mostrar eventos recientes.</li>\n</ul>\n<h5 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h5>\n<ul>\n<li><strong>Descubrimiento y Planificación:</strong> Definición de la marca con un enfoque interactivo y visualmente atractivo.</li>\n<li><strong>Diseño UX/UI:</strong> Desarrollo de un diseño claro con secciones como “Shows”, “Trailer”, “Bio” y “Contacto” para mejorar la navegación y el compromiso.</li>\n<li><strong>Estrategia de Contenido:</strong> Organización del contenido en torno a la experiencia y testimonios de Michel para generar credibilidad.</li>\n<li><strong>Elementos Interactivos:</strong> Adición de características atractivas como un “Trailer” y una “Galería” para aumentar la interacción en la página.</li>\n<li><strong>Pruebas y Optimización:</strong> Realización de pruebas de velocidad y usabilidad para garantizar una experiencia de usuario fluida y efectividad como landing page para el tráfico de redes sociales.</li>\n</ul>\n<h5 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h5>\n<ul>\n<li><strong>WordPress:</strong> Elegido para la gestión de contenido que permite actualizaciones sencillas.</li>\n<li><strong>DIVI Builder:</strong> Usado para un diseño modular personalizado que resalta servicios y testimonios.</li>\n<li><strong>HTML/CSS/JS Personalizados:</strong> Integración de elementos interactivos para mejorar la experiencia del usuario sin afectar los tiempos de carga.</li>\n</ul>\n<h5 id=\"resultados-e-impacto\">Resultados e Impacto</h5>\n<ul>\n<li><strong>Mayores Conversiones:</strong> La landing page optimizada llevó a un aumento en el compromiso y las reservas.</li>\n<li><strong>Identidad de Marca Mejorada:</strong> El sitio profesional y atractivo establece a Michel como un mentalista líder.</li>\n<li><strong>Empoderamiento del Cliente:</strong> Michel ahora puede gestionar actualizaciones de forma independiente, mostrando consistentemente su trabajo más reciente.</li>\n</ul>",{headings:156,localImagePaths:163,remoteImagePaths:164,frontmatter:165,imagePaths:169},[157,158,160,161,162],{depth:37,slug:88,text:89},{depth:159,slug:42,text:43},5,{depth:159,slug:45,text:46},{depth:159,slug:51,text:52},{depth:159,slug:54,text:55},[],[],{title:138,publishDate:166,img:143,img_alt:144,description:139,tags:167,screenshots:168},["Date","2020-03-02T00:00:00.000Z"],[20,18,142],[146,147,148,149],[],"portfolio",{id:170,data:172,body:186,filePath:187,digest:188,rendered:189},{title:173,description:174,publishDate:175,tags:176,img:177,img_alt:178,screenshots:179},"Rodrigo Camino Sitio Web de Portafolio","Este artículo describe mi sitio web de portafolio, diseñado para mostrar mis habilidades en desarrollo web y creatividad. Usando Astro, Tailwind CSS, HTML y JavaScript, el sitio se centra en un rendimiento rápido, actualizaciones sencillas y un diseño atractivo para mejorar mi marca y mantener el contenido actualizado.\n",["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],"/assets/portfolio/1.png","Screenshot del sitio web de Rodrigo",[180,181,182,183,184,185],"/assets/portfolio/2.png","/assets/portfolio/3.png","/assets/portfolio/4.png","/assets/portfolio/5.png","/assets/portfolio/6.png","/assets/portfolio/7.png","### Resumen del Proyecto\nEste sitio de portafolio es mi vitrina profesional, fusionando mis habilidades en desarrollo web y mi lado creativo como diseñador, destacando tanto mi experiencia técnica como mi enfoque estratégico e imaginativo a través de elementos interactivos y un diseño visual atractivo.\n\n### Objetivos\n- **Presencia Digital**: Establecer un sitio pulido y moderno que refleje mis fortalezas técnicas y creativas.\n- **Interacción del Usuario**: Proporcionar una experiencia interactiva que muestre mis proyectos de manera efectiva.\n- **Rendimiento**: Lograr un sitio optimizado y de carga rápida aprovechando Astro y Tailwind CSS.\n- **Mantenibilidad**: Asegurarme de que puedo actualizar fácilmente el sitio con nuevos proyectos y contenido a medida que se desarrollen.\n\n### Flujo de Trabajo del Proyecto\n- **Planificación y Descubrimiento**: Centrado en definir mi marca, asegurando que el flujo de usuarios sea acogedor y práctico.\n- **Diseño y Desarrollo**:\n  - **Diseño UI/UX**: Construí un diseño minimalista y limpio con navegación intuitiva.\n  - **Estructura Basada en Componentes**: Utilicé Astro y Tailwind CSS para crear componentes modulares, mejorando los tiempos de carga y la capacidad de respuesta.\n- **Estructuración del Contenido**: Organicé secciones como \"Acerca de\", \"Trabajo\" y \"Contacto\" para mostrar experiencia y proyectos de manera eficiente.\n- **Pruebas y Optimización**: Realicé pruebas de rendimiento, asegurando una carga suave y compatibilidad entre dispositivos.\n\n### Tecnologías Utilizadas\n- **Astro**: Utilizado para crear un sitio estático con un rendimiento excelente.\n- **Tailwind CSS**: Permite ajustes de estilo rápidos y flexibles.\n- **HTML y JavaScript**: Integrados para elementos dinámicos, mejorando la interactividad sin ralentizar el rendimiento.\n\n### Resultados e Impacto\n- **Imagen de Marca Mejorada**: Creé un diseño profesional y elegante que destaca mi combinación única de habilidades técnicas y creativas.\n- **Mayor Participación**: El diseño interactivo anima a los visitantes a explorar mis proyectos y habilidades, aumentando la participación.\n- **Empoderamiento del Cliente**: Con una estructura fácilmente mantenible, puedo mantener mi sitio actualizado y reflejar mi trabajo más reciente.","src/content/proyectos/Portfolio.md","7f11d796359b3357",{html:190,metadata:191},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>Este sitio de portafolio es mi vitrina profesional, fusionando mis habilidades en desarrollo web y mi lado creativo como diseñador, destacando tanto mi experiencia técnica como mi enfoque estratégico e imaginativo a través de elementos interactivos y un diseño visual atractivo.</p>\n<h3 id=\"objetivos\">Objetivos</h3>\n<ul>\n<li><strong>Presencia Digital</strong>: Establecer un sitio pulido y moderno que refleje mis fortalezas técnicas y creativas.</li>\n<li><strong>Interacción del Usuario</strong>: Proporcionar una experiencia interactiva que muestre mis proyectos de manera efectiva.</li>\n<li><strong>Rendimiento</strong>: Lograr un sitio optimizado y de carga rápida aprovechando Astro y Tailwind CSS.</li>\n<li><strong>Mantenibilidad</strong>: Asegurarme de que puedo actualizar fácilmente el sitio con nuevos proyectos y contenido a medida que se desarrollen.</li>\n</ul>\n<h3 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h3>\n<ul>\n<li><strong>Planificación y Descubrimiento</strong>: Centrado en definir mi marca, asegurando que el flujo de usuarios sea acogedor y práctico.</li>\n<li><strong>Diseño y Desarrollo</strong>:\n<ul>\n<li><strong>Diseño UI/UX</strong>: Construí un diseño minimalista y limpio con navegación intuitiva.</li>\n<li><strong>Estructura Basada en Componentes</strong>: Utilicé Astro y Tailwind CSS para crear componentes modulares, mejorando los tiempos de carga y la capacidad de respuesta.</li>\n</ul>\n</li>\n<li><strong>Estructuración del Contenido</strong>: Organicé secciones como “Acerca de”, “Trabajo” y “Contacto” para mostrar experiencia y proyectos de manera eficiente.</li>\n<li><strong>Pruebas y Optimización</strong>: Realicé pruebas de rendimiento, asegurando una carga suave y compatibilidad entre dispositivos.</li>\n</ul>\n<h3 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h3>\n<ul>\n<li><strong>Astro</strong>: Utilizado para crear un sitio estático con un rendimiento excelente.</li>\n<li><strong>Tailwind CSS</strong>: Permite ajustes de estilo rápidos y flexibles.</li>\n<li><strong>HTML y JavaScript</strong>: Integrados para elementos dinámicos, mejorando la interactividad sin ralentizar el rendimiento.</li>\n</ul>\n<h3 id=\"resultados-e-impacto\">Resultados e Impacto</h3>\n<ul>\n<li><strong>Imagen de Marca Mejorada</strong>: Creé un diseño profesional y elegante que destaca mi combinación única de habilidades técnicas y creativas.</li>\n<li><strong>Mayor Participación</strong>: El diseño interactivo anima a los visitantes a explorar mis proyectos y habilidades, aumentando la participación.</li>\n<li><strong>Empoderamiento del Cliente</strong>: Con una estructura fácilmente mantenible, puedo mantener mi sitio actualizado y reflejar mi trabajo más reciente.</li>\n</ul>",{headings:192,localImagePaths:198,remoteImagePaths:199,frontmatter:200,imagePaths:204},[193,194,195,196,197],{depth:37,slug:88,text:89},{depth:37,slug:42,text:43},{depth:37,slug:45,text:46},{depth:37,slug:51,text:52},{depth:37,slug:54,text:55},[],[],{title:173,publishDate:201,img:177,img_alt:178,description:174,tags:202,screenshots:203},["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],[180,181,182,183,184,185],[],"robertomansilla",{id:205,data:207,body:220,filePath:221,digest:222,rendered:223},{title:208,description:209,publishDate:210,tags:211,img:213,img_alt:214,screenshots:215},"Roberto Mansilla sitio web.","Roberto Mansilla, un destacado mentalista argentino, necesitaba un sitio web que resalte sus espectáculos únicos y funcione como una landing page de alta conversión para el tráfico de redes sociales.\n",["Date","2024-09-08T00:00:00.000Z"],[212,18,142],"Design","/assets/mansilla/1.webp","Screenshot del sitio de Roberto.",[216,217,218,219],"/assets/mansilla/2.png","/assets/mansilla/3.png","/assets/mansilla/4.png","/assets/mansilla/5.png","### Resumen del Proyecto\nRoberto Mansilla requería un sitio que mostrara sus shows y facilitara conversiones desde redes sociales, con un diseño que presenta una navegación \"tipo plato\" y animaciones atractivas que capturan la esencia de su estilo de actuación.\n\n### Objetivos\n- **Autoridad de Marca**: Posicionar a Roberto como un mentalista líder con un sitio visualmente memorable.\n- **Embudo de Participación del Usuario**: Facilitar la transición de visitantes de redes sociales al sitio, enfocándose en la conversión de reservas.\n- **Diseño UX Interactivo**: Integrar animaciones que mejoren la experiencia y reflejen el misticismo de las actuaciones de Roberto.\n- **Capacidad de Autogestión**: Permitir que Roberto actualice de manera independiente shows y testimonios.\n\n### Flujo de Trabajo del Proyecto\n1. **Descubrimiento y Estrategia**: Definición de la marca digital de Roberto con un diseño único que refuerza su presencia escénica.\n2. **Diseño UI/UX**: Creación de una interfaz interactiva con navegación \"tipo plato\" para shows, testimonios y un tráiler en video.\n3. **Estrategia de Contenido**: Organización de contenido para resaltar categorías principales de shows y testimonios del público.\n4. **Elementos Interactivos**: Incorporación de animaciones en JavaScript que aportan intriga y mejoran la participación sin afectar el rendimiento del sitio.\n5. **Pruebas y Optimización**: Optimización para SEO y reducción de tiempos de carga para asegurar que el sitio funcione eficazmente como una landing page enfocada en la conversión.\n\n### Tecnologías Utilizadas\n- **WordPress**: Seleccionado por su gestión de contenido flexible y fácil de usar.\n- **DIVI Builder**: Permite un diseño modular adecuado para mostrar los servicios de Roberto.\n- **HTML/CSS/JS**: Animaciones elaboradas para una UX atractiva sin afectar los tiempos de carga.\n\n### Resultados e Impacto\n- **Mayor Participación y Conversión**: La landing page estructurada aumenta las reservas desde redes sociales.\n- **Mejora en la Presencia de Marca**: Un diseño pulido y dinámico establece la autoridad de Roberto en el campo del mentalismo.\n- **Facilidad de Gestión**: Roberto ahora puede gestionar el contenido de forma independiente, manteniendo su sitio actualizado con shows y testimonios recientes.","src/content/proyectos/RobertoMansilla.md","211194e4f700388b",{html:224,metadata:225},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>Roberto Mansilla requería un sitio que mostrara sus shows y facilitara conversiones desde redes sociales, con un diseño que presenta una navegación “tipo plato” y animaciones atractivas que capturan la esencia de su estilo de actuación.</p>\n<h3 id=\"objetivos\">Objetivos</h3>\n<ul>\n<li><strong>Autoridad de Marca</strong>: Posicionar a Roberto como un mentalista líder con un sitio visualmente memorable.</li>\n<li><strong>Embudo de Participación del Usuario</strong>: Facilitar la transición de visitantes de redes sociales al sitio, enfocándose en la conversión de reservas.</li>\n<li><strong>Diseño UX Interactivo</strong>: Integrar animaciones que mejoren la experiencia y reflejen el misticismo de las actuaciones de Roberto.</li>\n<li><strong>Capacidad de Autogestión</strong>: Permitir que Roberto actualice de manera independiente shows y testimonios.</li>\n</ul>\n<h3 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h3>\n<ol>\n<li><strong>Descubrimiento y Estrategia</strong>: Definición de la marca digital de Roberto con un diseño único que refuerza su presencia escénica.</li>\n<li><strong>Diseño UI/UX</strong>: Creación de una interfaz interactiva con navegación “tipo plato” para shows, testimonios y un tráiler en video.</li>\n<li><strong>Estrategia de Contenido</strong>: Organización de contenido para resaltar categorías principales de shows y testimonios del público.</li>\n<li><strong>Elementos Interactivos</strong>: Incorporación de animaciones en JavaScript que aportan intriga y mejoran la participación sin afectar el rendimiento del sitio.</li>\n<li><strong>Pruebas y Optimización</strong>: Optimización para SEO y reducción de tiempos de carga para asegurar que el sitio funcione eficazmente como una landing page enfocada en la conversión.</li>\n</ol>\n<h3 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h3>\n<ul>\n<li><strong>WordPress</strong>: Seleccionado por su gestión de contenido flexible y fácil de usar.</li>\n<li><strong>DIVI Builder</strong>: Permite un diseño modular adecuado para mostrar los servicios de Roberto.</li>\n<li><strong>HTML/CSS/JS</strong>: Animaciones elaboradas para una UX atractiva sin afectar los tiempos de carga.</li>\n</ul>\n<h3 id=\"resultados-e-impacto\">Resultados e Impacto</h3>\n<ul>\n<li><strong>Mayor Participación y Conversión</strong>: La landing page estructurada aumenta las reservas desde redes sociales.</li>\n<li><strong>Mejora en la Presencia de Marca</strong>: Un diseño pulido y dinámico establece la autoridad de Roberto en el campo del mentalismo.</li>\n<li><strong>Facilidad de Gestión</strong>: Roberto ahora puede gestionar el contenido de forma independiente, manteniendo su sitio actualizado con shows y testimonios recientes.</li>\n</ul>",{headings:226,localImagePaths:232,remoteImagePaths:233,frontmatter:234,imagePaths:238},[227,228,229,230,231],{depth:37,slug:88,text:89},{depth:37,slug:42,text:43},{depth:37,slug:45,text:46},{depth:37,slug:51,text:52},{depth:37,slug:54,text:55},[],[],{title:208,publishDate:235,img:213,img_alt:214,description:209,tags:236,screenshots:237},["Date","2024-09-08T00:00:00.000Z"],[212,18,142],[216,217,218,219],[],"santiago",{id:239,data:241,body:256,filePath:257,digest:258,rendered:259},{title:242,description:243,publishDate:244,tags:245,img:246,img_alt:247,screenshots:248,video:255},"Santiago Ilusionista Sitio web","Creado para servir como un portafolio y una landing page enfocada en la conversión.\n",["Date","2024-06-29T00:00:00.000Z"],[212,18,142],"/assets/santi/1.webp","Screenshot del sitio web de Santiago.",[249,250,251,252,253,254],"/assets/santi/2.webp","/assets/santi/3.webp","/assets/santi/4.webp","/assets/santi/5.webp","/assets/santi/6.webp","/assets/santi/7.webp","/assets/santi/1.mp4","### Resumen del Proyecto\nEl sitio web de Santiago Fernández es una landing page dinámica diseñada para presentar a Santiago, un destacado mago, y atraer audiencias para diversos eventos: corporativos, privados y teatrales. Construido como una plataforma de alta conversión, el sitio aprovecha los embudos de redes sociales para involucrar a los visitantes y generar consultas de reservas.\n\n#### Objetivos\n- **Presencia Digital**: Posicionar a Santiago como un mago de primer nivel en Argentina y España.\n- **Optimización de Conversión**: Crear una landing page optimizada para convertir el tráfico de redes sociales y aumentar las reservas de eventos.\n- **Rendimiento y Accesibilidad**: Asegurar tiempos de carga rápidos y una interfaz accesible y fácil de usar.\n- **Flexibilidad de Contenido**: Permitir que Santiago actualice fácilmente eventos recientes y testimonios para mantenerse al día con sus actuaciones.\n\n#### Flujo de Trabajo del Proyecto\n- **Descubrimiento y Planificación**: Se estableció un sitio centrado en la marca con un enfoque de diseño moderno e interactivo.\n- **Diseño UX/UI**: Se estructuró el contenido en secciones claras para servicios, galerías y testimonios para construir confianza y participación de los visitantes.\n- **Estrategia de Contenido**: Se centró en la experiencia única de Santiago y los comentarios reales de los clientes para cautivar y convertir a los visitantes del sitio.\n- **Elementos Interactivos**: Se integró una galería de medios, varias categorías de eventos y funciones de redes sociales para una mayor participación.\n- **Pruebas y Optimización**: Se realizaron pruebas de usabilidad y velocidad para garantizar un rendimiento óptimo como landing page para redes sociales.\n\n#### Tecnologías Utilizadas\n- **WordPress**: Para una gestión de contenido eficiente y actualizaciones fáciles.\n- **DIVI Builder**: Permite un diseño modular y un layout personalizable para mejorar la participación.\n- **HTML/CSS/JavaScript**: Se aplicó código personalizado para elementos interactivos, minimizando la carga de plugins para un mejor rendimiento.\n\n#### Resultados e Impacto\n- **Aumento de Reservas**: La landing page optimizada impulsa efectivamente la participación, convirtiendo a los visitantes de redes sociales en clientes.\n- **Fortalecimiento de la Autoridad de Marca**: El sitio pulido y profesional refuerza la posición de Santiago como un mago líder.\n- **Empoderamiento del Cliente**: Santiago puede actualizar su sitio de manera independiente para reflejar eventos recientes y añadir testimonios, manteniendo el interés de los usuarios.","src/content/proyectos/Santiago.md","3a7a7223db80e7fe",{html:260,metadata:261},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>El sitio web de Santiago Fernández es una landing page dinámica diseñada para presentar a Santiago, un destacado mago, y atraer audiencias para diversos eventos: corporativos, privados y teatrales. Construido como una plataforma de alta conversión, el sitio aprovecha los embudos de redes sociales para involucrar a los visitantes y generar consultas de reservas.</p>\n<h4 id=\"objetivos\">Objetivos</h4>\n<ul>\n<li><strong>Presencia Digital</strong>: Posicionar a Santiago como un mago de primer nivel en Argentina y España.</li>\n<li><strong>Optimización de Conversión</strong>: Crear una landing page optimizada para convertir el tráfico de redes sociales y aumentar las reservas de eventos.</li>\n<li><strong>Rendimiento y Accesibilidad</strong>: Asegurar tiempos de carga rápidos y una interfaz accesible y fácil de usar.</li>\n<li><strong>Flexibilidad de Contenido</strong>: Permitir que Santiago actualice fácilmente eventos recientes y testimonios para mantenerse al día con sus actuaciones.</li>\n</ul>\n<h4 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h4>\n<ul>\n<li><strong>Descubrimiento y Planificación</strong>: Se estableció un sitio centrado en la marca con un enfoque de diseño moderno e interactivo.</li>\n<li><strong>Diseño UX/UI</strong>: Se estructuró el contenido en secciones claras para servicios, galerías y testimonios para construir confianza y participación de los visitantes.</li>\n<li><strong>Estrategia de Contenido</strong>: Se centró en la experiencia única de Santiago y los comentarios reales de los clientes para cautivar y convertir a los visitantes del sitio.</li>\n<li><strong>Elementos Interactivos</strong>: Se integró una galería de medios, varias categorías de eventos y funciones de redes sociales para una mayor participación.</li>\n<li><strong>Pruebas y Optimización</strong>: Se realizaron pruebas de usabilidad y velocidad para garantizar un rendimiento óptimo como landing page para redes sociales.</li>\n</ul>\n<h4 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h4>\n<ul>\n<li><strong>WordPress</strong>: Para una gestión de contenido eficiente y actualizaciones fáciles.</li>\n<li><strong>DIVI Builder</strong>: Permite un diseño modular y un layout personalizable para mejorar la participación.</li>\n<li><strong>HTML/CSS/JavaScript</strong>: Se aplicó código personalizado para elementos interactivos, minimizando la carga de plugins para un mejor rendimiento.</li>\n</ul>\n<h4 id=\"resultados-e-impacto\">Resultados e Impacto</h4>\n<ul>\n<li><strong>Aumento de Reservas</strong>: La landing page optimizada impulsa efectivamente la participación, convirtiendo a los visitantes de redes sociales en clientes.</li>\n<li><strong>Fortalecimiento de la Autoridad de Marca</strong>: El sitio pulido y profesional refuerza la posición de Santiago como un mago líder.</li>\n<li><strong>Empoderamiento del Cliente</strong>: Santiago puede actualizar su sitio de manera independiente para reflejar eventos recientes y añadir testimonios, manteniendo el interés de los usuarios.</li>\n</ul>",{headings:262,localImagePaths:268,remoteImagePaths:269,frontmatter:270,imagePaths:274},[263,264,265,266,267],{depth:37,slug:88,text:89},{depth:41,slug:42,text:43},{depth:41,slug:45,text:46},{depth:41,slug:51,text:52},{depth:41,slug:54,text:55},[],[],{title:242,publishDate:271,img:246,img_alt:247,description:243,tags:272,screenshots:273,video:255},["Date","2024-06-29T00:00:00.000Z"],[212,18,142],[249,250,251,252,253,254],[],"sdi",{id:275,data:277,body:288,filePath:289,digest:290,rendered:291},{title:278,description:279,publishDate:280,tags:281,img:282,img_alt:283,screenshots:284},"Sujetos del Inconsciente Sitio y Blog","El sitio web Sujetos del Inconsciente funciona como una plataforma educativa de psicología centrada en la salud mental y el psicoanálisis.\n",["Date","2024-10-02T00:00:00.000Z"],[212,19,20,72],"/assets/SDIweb.webp","Screenshot de Sujetos del Inconsciente Sitio y Blog.",[285,286,287],"/assets/SDI/1.png","/assets/SDI/2.png","/assets/SDI/3.png","### Resumen del Proyecto\nEste sitio ofrece artículos, reflexiones y recursos para usuarios interesados en explorar temas psicológicos y filosóficos, estableciendo un espacio acogedor para el aprendizaje y la reflexión.\n\n#### Objetivos\n- **Presencia Digital:** Fortalecer la autoridad en salud mental y psicoanálisis.\n- **Interacción:** Fomentar la interacción a través de un formato de blog estructurado.\n- **SEO y Accesibilidad:** Mejorar el alcance orgánico y la accesibilidad para usuarios diversos.\n- **CMS amigable:** Permitir actualizaciones y gestión de contenido fáciles.\n\n##### Flujo de Trabajo del Proyecto\n- **Planificación:** Se estableció una identidad de marca clara y una estrategia de contenido, centrada en temas psicoanalíticos.\n- **Diseño y UX:** Se desarrolló un diseño limpio e intuitivo con secciones claras como \"Sobre,\" \"Blog\" y \"Contacto\" para una navegación fluida.\n- **Estrategia de Contenido:** Se organizaron las estructuras de los artículos en torno a temas psicoanalíticos centrales como identidad, autoestima y filosofía educativa.\n- **Funciones Dinámicas:** Se incorporaron enlaces a redes sociales para fomentar la participación de la comunidad.\n- **Pruebas:** Se llevaron a cabo evaluaciones de rendimiento para optimizar la accesibilidad y la experiencia del usuario.\n\n##### Tecnologías Utilizadas\n- **WordPress:** Para una gestión de contenido eficiente y actualizaciones fáciles.\n- **DIVI Builder:** Permitió personalización de diseño modular y flexible.\n- **Código Personalizado (HTML/CSS/JS):** Se añadieron elementos únicos de UI/UX para una experiencia de usuario cohesiva y profesional.\n\n##### Resultados e Impacto\n- **Mayor Participación:** El blog estructurado y las funciones interactivas facilitan la participación del usuario.\n- **Identidad de Marca Mejorada:** Se creó una plataforma accesible que establece al cliente como una voz de confianza en salud mental.\n- **Empoderamiento del Usuario:** El cliente ahora puede gestionar actualizaciones de contenido de manera autónoma, permitiendo una participación constante y una presencia en línea sostenible.","src/content/proyectos/SDI.md","414e4e10033a926a",{html:292,metadata:293},"<h3 id=\"resumen-del-proyecto\">Resumen del Proyecto</h3>\n<p>Este sitio ofrece artículos, reflexiones y recursos para usuarios interesados en explorar temas psicológicos y filosóficos, estableciendo un espacio acogedor para el aprendizaje y la reflexión.</p>\n<h4 id=\"objetivos\">Objetivos</h4>\n<ul>\n<li><strong>Presencia Digital:</strong> Fortalecer la autoridad en salud mental y psicoanálisis.</li>\n<li><strong>Interacción:</strong> Fomentar la interacción a través de un formato de blog estructurado.</li>\n<li><strong>SEO y Accesibilidad:</strong> Mejorar el alcance orgánico y la accesibilidad para usuarios diversos.</li>\n<li><strong>CMS amigable:</strong> Permitir actualizaciones y gestión de contenido fáciles.</li>\n</ul>\n<h5 id=\"flujo-de-trabajo-del-proyecto\">Flujo de Trabajo del Proyecto</h5>\n<ul>\n<li><strong>Planificación:</strong> Se estableció una identidad de marca clara y una estrategia de contenido, centrada en temas psicoanalíticos.</li>\n<li><strong>Diseño y UX:</strong> Se desarrolló un diseño limpio e intuitivo con secciones claras como “Sobre,” “Blog” y “Contacto” para una navegación fluida.</li>\n<li><strong>Estrategia de Contenido:</strong> Se organizaron las estructuras de los artículos en torno a temas psicoanalíticos centrales como identidad, autoestima y filosofía educativa.</li>\n<li><strong>Funciones Dinámicas:</strong> Se incorporaron enlaces a redes sociales para fomentar la participación de la comunidad.</li>\n<li><strong>Pruebas:</strong> Se llevaron a cabo evaluaciones de rendimiento para optimizar la accesibilidad y la experiencia del usuario.</li>\n</ul>\n<h5 id=\"tecnologías-utilizadas\">Tecnologías Utilizadas</h5>\n<ul>\n<li><strong>WordPress:</strong> Para una gestión de contenido eficiente y actualizaciones fáciles.</li>\n<li><strong>DIVI Builder:</strong> Permitió personalización de diseño modular y flexible.</li>\n<li><strong>Código Personalizado (HTML/CSS/JS):</strong> Se añadieron elementos únicos de UI/UX para una experiencia de usuario cohesiva y profesional.</li>\n</ul>\n<h5 id=\"resultados-e-impacto\">Resultados e Impacto</h5>\n<ul>\n<li><strong>Mayor Participación:</strong> El blog estructurado y las funciones interactivas facilitan la participación del usuario.</li>\n<li><strong>Identidad de Marca Mejorada:</strong> Se creó una plataforma accesible que establece al cliente como una voz de confianza en salud mental.</li>\n<li><strong>Empoderamiento del Usuario:</strong> El cliente ahora puede gestionar actualizaciones de contenido de manera autónoma, permitiendo una participación constante y una presencia en línea sostenible.</li>\n</ul>",{headings:294,localImagePaths:300,remoteImagePaths:301,frontmatter:302,imagePaths:306},[295,296,297,298,299],{depth:37,slug:88,text:89},{depth:41,slug:42,text:43},{depth:159,slug:45,text:46},{depth:159,slug:51,text:52},{depth:159,slug:54,text:55},[],[],{title:278,publishDate:303,img:282,img_alt:283,description:279,tags:304,screenshots:305},["Date","2024-10-02T00:00:00.000Z"],[212,19,20,72],[285,286,287],[],"work",["Map",11,309,63,366,101,393,135,420,170,449,205,476,239,503,275,529],{id:11,data:310,body:316,filePath:317,digest:318,rendered:319},{title:311,description:312,publishDate:313,tags:314,img:21,img_alt:22,screenshots:315},"CAPFA Constructora Website Revamp","CAPFA Constructora sought a comprehensive digital transformation to improve performance, SEO, and user experience. Their previous website, with a 45% performance score, felt outdated and lacked engagement. \n",["Date","2019-12-01T00:00:00.000Z"],[18,19,20],[24,25,26,27,28],"### Project Overview\n\nOur goals were to enhance speed, optimize SEO, modernize the UX/UI, and introduce a component-driven structure for higher software quality and maintainability.\n\n##### Objectives\n- <b>Performance and Accessibility:</b> Raise Google Lighthouse scores.\n###\n- <b>Usability and Engagement:</b> Redesign UX/UI to reflect CAPFA’s brand.\n###\n- <b>Ease of Updates:</b> Enable CAPFA to update the site regularly via WordPress and DIVI.\n###\n- <b> Digital Presence:</b> Increase engagement through social media integration and a user-focused design.\n###\n#### Project Workflow\n<b>Discovery and Planning:</b> Established CAPFA’s brand identity with a custom color palette, typography, and wireframes to boost user engagement.\n###\n##### Design and Development:\n- <b>Page Structuring:</b> Developed templates for pages like \"Contact,\" \"About Us,\" and \"Projects.\"\n\n- <b>SEO and Accessibility:</b> Utilized DIVI’s native tools for optimized SEO and accessibility.\n\n- <b>Component-Driven Structure:</b> Incorporated custom PHP functions and DIVI’s modular tools for streamlined backend management.\n\n- <b>Dynamic Features:</b> Implemented JavaScript for an interactive WhatsApp button without performance-impacting plugins.\n\n- <b>Testing and Optimization:</b> Achieved a 94% Google Lighthouse performance score with further validation through Google Analytics and additional testing tools.\n\n- <b>Execution Timeline:</b> Followed a structured weekly timeline to ensure project completion on schedule.\n###\n##### Technologies Used\n><b>WordPress:</b> For easy client updates.\n###\n><b>DIVI:</b> For modularity and SEO capabilities.\n###\n><b>PHP, JavaScript, HTML, CSS:</b> \n#####\n>Applied for custom functionality, styling, and optimized interactivity without added plugin loads.\n\n##### Results and Impact\n\n- <b>Performance:</b> Boosted Lighthouse score from 45% to 94%, delivering faster load times and enhanced user retention.\n\n- <b>Usability and Engagement:</b> Improved user interaction and accessibility, enabling seamless connections between CAPFA’s social media and website.\n\n- <b>Client Empowerment:</b> CAPFA now manages content updates independently, solidifying its digital presence and engagement strategy.","src/content/work/CAPFA.md","7cc0b84d37ad08ef",{html:320,metadata:321},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>Our goals were to enhance speed, optimize SEO, modernize the UX/UI, and introduce a component-driven structure for higher software quality and maintainability.</p>\n<h5 id=\"objectives\">Objectives</h5>\n<ul>\n<li><b>Performance and Accessibility:</b> Raise Google Lighthouse scores.</li>\n</ul>\n<h3 id=\"\"></h3>\n<ul>\n<li><b>Usability and Engagement:</b> Redesign UX/UI to reflect CAPFA’s brand.</li>\n</ul>\n<h3 id=\"-1\"></h3>\n<ul>\n<li><b>Ease of Updates:</b> Enable CAPFA to update the site regularly via WordPress and DIVI.</li>\n</ul>\n<h3 id=\"-2\"></h3>\n<ul>\n<li><b> Digital Presence:</b> Increase engagement through social media integration and a user-focused design.</li>\n</ul>\n<h3 id=\"-3\"></h3>\n<h4 id=\"project-workflow\">Project Workflow</h4>\n<p><b>Discovery and Planning:</b> Established CAPFA’s brand identity with a custom color palette, typography, and wireframes to boost user engagement.</p>\n<h3 id=\"-4\"></h3>\n<h5 id=\"design-and-development\">Design and Development:</h5>\n<ul>\n<li>\n<p><b>Page Structuring:</b> Developed templates for pages like “Contact,” “About Us,” and “Projects.”</p>\n</li>\n<li>\n<p><b>SEO and Accessibility:</b> Utilized DIVI’s native tools for optimized SEO and accessibility.</p>\n</li>\n<li>\n<p><b>Component-Driven Structure:</b> Incorporated custom PHP functions and DIVI’s modular tools for streamlined backend management.</p>\n</li>\n<li>\n<p><b>Dynamic Features:</b> Implemented JavaScript for an interactive WhatsApp button without performance-impacting plugins.</p>\n</li>\n<li>\n<p><b>Testing and Optimization:</b> Achieved a 94% Google Lighthouse performance score with further validation through Google Analytics and additional testing tools.</p>\n</li>\n<li>\n<p><b>Execution Timeline:</b> Followed a structured weekly timeline to ensure project completion on schedule.</p>\n</li>\n</ul>\n<h3 id=\"-5\"></h3>\n<h5 id=\"technologies-used\">Technologies Used</h5>\n<blockquote>\n<p><b>WordPress:</b> For easy client updates.</p>\n</blockquote>\n<h3 id=\"-6\"></h3>\n<blockquote>\n<p><b>DIVI:</b> For modularity and SEO capabilities.</p>\n</blockquote>\n<h3 id=\"-7\"></h3>\n<blockquote>\n<p><b>PHP, JavaScript, HTML, CSS:</b></p>\n</blockquote>\n<h5 id=\"-8\"></h5>\n<blockquote>\n<p>Applied for custom functionality, styling, and optimized interactivity without added plugin loads.</p>\n</blockquote>\n<h5 id=\"results-and-impact\">Results and Impact</h5>\n<ul>\n<li>\n<p><b>Performance:</b> Boosted Lighthouse score from 45% to 94%, delivering faster load times and enhanced user retention.</p>\n</li>\n<li>\n<p><b>Usability and Engagement:</b> Improved user interaction and accessibility, enabling seamless connections between CAPFA’s social media and website.</p>\n</li>\n<li>\n<p><b>Client Empowerment:</b> CAPFA now manages content updates independently, solidifying its digital presence and engagement strategy.</p>\n</li>\n</ul>",{headings:322,localImagePaths:359,remoteImagePaths:360,frontmatter:361,imagePaths:365},[323,326,329,331,333,335,337,340,342,345,347,350,352,354,356],{depth:37,slug:324,text:325},"project-overview","Project Overview",{depth:159,slug:327,text:328},"objectives","Objectives",{depth:37,slug:330,text:330},"",{depth:37,slug:332,text:330},"-1",{depth:37,slug:334,text:330},"-2",{depth:37,slug:336,text:330},"-3",{depth:41,slug:338,text:339},"project-workflow","Project Workflow",{depth:37,slug:341,text:330},"-4",{depth:159,slug:343,text:344},"design-and-development","Design and Development:",{depth:37,slug:346,text:330},"-5",{depth:159,slug:348,text:349},"technologies-used","Technologies Used",{depth:37,slug:351,text:330},"-6",{depth:37,slug:353,text:330},"-7",{depth:159,slug:355,text:330},"-8",{depth:159,slug:357,text:358},"results-and-impact","Results and Impact",[],[],{title:311,publishDate:362,img:21,img_alt:22,description:312,tags:363,screenshots:364},["Date","2019-12-01T00:00:00.000Z"],[18,19,20],[24,25,26,27,28],[],{id:63,data:367,body:374,filePath:375,digest:376,rendered:377},{title:368,description:369,publishDate:370,tags:371,img:73,img_alt:372,screenshots:373},"Larry Props Interactive E-Commerce Website","The Larry Props website serves a niche market in high-quality mentalism props, offering professional tools tailored for performers.\n",["Date","2019-02-02T00:00:00.000Z"],[212,19,20,72],"Screenshot of SDI Web",[76,77,78,79],"### Project Overview\n As an interactive e-commerce platform, it prioritizes customer satisfaction, premium branding, and streamlined social media-driven conversions. The site’s design highlights craftsmanship and quality, while functionality supports direct sales and user engagement.\n\n#### Objectives\n- **E-Commerce Optimization:** Develop a user-friendly store emphasizing Larry Props' dedication to quality and uniqueness.\n- **Conversion Funnel:** Create a landing page that efficiently converts social media visitors into customers.\n- **SEO & Performance:** Enhance search visibility and reduce loading times for a smooth user experience.\n- **Client Independence:** Empower Larry Props to update content and manage inventory with ease.\n\n#### Project Workflow\n- **Planning:** Established a distinct brand identity focusing on quality and streamlined navigation.\n- **Design & Development:** Designed an intuitive UI with essential sections like “Shop,” “About,” and “Contact” for a seamless experience.\n- **Dynamic Components:** Employed DIVI’s modular design and custom code to present product descriptions, media, and customer testimonials.\n- **Testing & Optimization:** Conducted performance evaluations, achieving fast load times and smooth interactions for better user experience.\n\n#### Technologies Used\n- **WordPress & DIVI:** Flexible content management and design customization.\n- **Custom HTML/CSS/JavaScript:** Interactive functionalities optimized for e-commerce without heavy plugins.\n\n#### Results and Impact\n- **Conversion Increase:** Optimized landing page led to higher user engagement and increased sales conversions.\n- **Brand Growth:** Enhanced credibility and recognition as a premium provider in the mentalism community.\n- **Client Flexibility:** Larry Props now easily manages product listings and inventory, supporting a dynamic and evolving product lineup.","src/content/work/Larry.md","a6b9767ec2927d02",{html:378,metadata:379},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>As an interactive e-commerce platform, it prioritizes customer satisfaction, premium branding, and streamlined social media-driven conversions. The site’s design highlights craftsmanship and quality, while functionality supports direct sales and user engagement.</p>\n<h4 id=\"objectives\">Objectives</h4>\n<ul>\n<li><strong>E-Commerce Optimization:</strong> Develop a user-friendly store emphasizing Larry Props’ dedication to quality and uniqueness.</li>\n<li><strong>Conversion Funnel:</strong> Create a landing page that efficiently converts social media visitors into customers.</li>\n<li><strong>SEO &#x26; Performance:</strong> Enhance search visibility and reduce loading times for a smooth user experience.</li>\n<li><strong>Client Independence:</strong> Empower Larry Props to update content and manage inventory with ease.</li>\n</ul>\n<h4 id=\"project-workflow\">Project Workflow</h4>\n<ul>\n<li><strong>Planning:</strong> Established a distinct brand identity focusing on quality and streamlined navigation.</li>\n<li><strong>Design &#x26; Development:</strong> Designed an intuitive UI with essential sections like “Shop,” “About,” and “Contact” for a seamless experience.</li>\n<li><strong>Dynamic Components:</strong> Employed DIVI’s modular design and custom code to present product descriptions, media, and customer testimonials.</li>\n<li><strong>Testing &#x26; Optimization:</strong> Conducted performance evaluations, achieving fast load times and smooth interactions for better user experience.</li>\n</ul>\n<h4 id=\"technologies-used\">Technologies Used</h4>\n<ul>\n<li><strong>WordPress &#x26; DIVI:</strong> Flexible content management and design customization.</li>\n<li><strong>Custom HTML/CSS/JavaScript:</strong> Interactive functionalities optimized for e-commerce without heavy plugins.</li>\n</ul>\n<h4 id=\"results-and-impact\">Results and Impact</h4>\n<ul>\n<li><strong>Conversion Increase:</strong> Optimized landing page led to higher user engagement and increased sales conversions.</li>\n<li><strong>Brand Growth:</strong> Enhanced credibility and recognition as a premium provider in the mentalism community.</li>\n<li><strong>Client Flexibility:</strong> Larry Props now easily manages product listings and inventory, supporting a dynamic and evolving product lineup.</li>\n</ul>",{headings:380,localImagePaths:386,remoteImagePaths:387,frontmatter:388,imagePaths:392},[381,382,383,384,385],{depth:37,slug:324,text:325},{depth:41,slug:327,text:328},{depth:41,slug:338,text:339},{depth:41,slug:348,text:349},{depth:41,slug:357,text:358},[],[],{title:368,publishDate:389,img:73,img_alt:372,description:369,tags:390,screenshots:391},["Date","2019-02-02T00:00:00.000Z"],[212,19,20,72],[76,77,78,79],[],{id:101,data:394,body:401,filePath:402,digest:403,rendered:404},{title:395,description:396,publishDate:397,tags:398,img:108,img_alt:399,screenshots:400},"Estudio Lena Website","Estudio Lena’s website serves as both a legal resource and contact hub for accident and injury cases, managed by a team of legal experts. \n",["Date","2019-12-01T00:00:00.000Z"],[18,19,20,72],"Screenshot of Studio Lena Website",[111,112,113,114,115],"### **Project Overview**\nEstudio Lena’s website serves as both a legal resource and contact hub for accident and injury cases, managed by a team of legal experts. This site doubles as a user conversion landing page, strategically designed to funnel traffic from social media into online “pre-case” initiation, streamlining both client onboarding and case management for the law firm.\n\n#### **Objectives**\n- **Digital Presence**: Reinforce Estudio Lena’s reputation in personal injury and accident law.\n- **User Conversion Funnel**: Engage social media-driven traffic and simplify the client intake process through an automated “pre-case” form.\n- **Streamlined Management System**: Enhance internal workflows with a tailored content management structure for team collaboration.\n- **Accessibility & SEO**: Optimize for accessibility, ensuring wide reach and easy usability.\n\n#### **Project Workflow**\n1. **Discovery & Planning**: Established a brand message and designed a legal-focused UX/UI to inspire trust and professionalism.\n2. **UX/UI Design**: Structured the site with clear navigation across pages like “About,” “Practice Areas,” and “Contact,” emphasizing user-friendly layout and smooth navigation.\n3. **Content Strategy**: Organized content around primary legal services, spotlighting areas like “Accidents” and “Free Consultations” to align with user search intent.\n4. **Automated Pre-Case Form**: Added a form that lets users initiate cases online, reducing intake times and enhancing client tracking for the legal team.\n5. **Testing & Optimization**: Performed usability and performance testing to verify site speed, SEO, and user experience.\n\n#### **Technologies Used**\n- **WordPress**: Provides easy content management and backend data tracking for the team.\n- **DIVI Builder**: Allows modular, flexible design suitable for evolving content needs.\n- **Custom HTML/CSS/JS**: Tailored dynamic features and streamlined form interactions for a smoother user experience.\n\n#### **Results and Impact**\n- **Improved Conversion Rate**: Social media-optimized landing page design increased client inquiries and conversions.\n- **Enhanced Workflow**: Automated “pre-case” initiation system improved intake efficiency and team collaboration.\n- **Brand Authority**: A professional and functional website establishes Estudio Lena as a leader in personal injury law, providing both credibility and convenience.","src/content/work/Lena.md","b17086f15cb9565d",{html:405,metadata:406},"<h3 id=\"project-overview\"><strong>Project Overview</strong></h3>\n<p>Estudio Lena’s website serves as both a legal resource and contact hub for accident and injury cases, managed by a team of legal experts. This site doubles as a user conversion landing page, strategically designed to funnel traffic from social media into online “pre-case” initiation, streamlining both client onboarding and case management for the law firm.</p>\n<h4 id=\"objectives\"><strong>Objectives</strong></h4>\n<ul>\n<li><strong>Digital Presence</strong>: Reinforce Estudio Lena’s reputation in personal injury and accident law.</li>\n<li><strong>User Conversion Funnel</strong>: Engage social media-driven traffic and simplify the client intake process through an automated “pre-case” form.</li>\n<li><strong>Streamlined Management System</strong>: Enhance internal workflows with a tailored content management structure for team collaboration.</li>\n<li><strong>Accessibility &#x26; SEO</strong>: Optimize for accessibility, ensuring wide reach and easy usability.</li>\n</ul>\n<h4 id=\"project-workflow\"><strong>Project Workflow</strong></h4>\n<ol>\n<li><strong>Discovery &#x26; Planning</strong>: Established a brand message and designed a legal-focused UX/UI to inspire trust and professionalism.</li>\n<li><strong>UX/UI Design</strong>: Structured the site with clear navigation across pages like “About,” “Practice Areas,” and “Contact,” emphasizing user-friendly layout and smooth navigation.</li>\n<li><strong>Content Strategy</strong>: Organized content around primary legal services, spotlighting areas like “Accidents” and “Free Consultations” to align with user search intent.</li>\n<li><strong>Automated Pre-Case Form</strong>: Added a form that lets users initiate cases online, reducing intake times and enhancing client tracking for the legal team.</li>\n<li><strong>Testing &#x26; Optimization</strong>: Performed usability and performance testing to verify site speed, SEO, and user experience.</li>\n</ol>\n<h4 id=\"technologies-used\"><strong>Technologies Used</strong></h4>\n<ul>\n<li><strong>WordPress</strong>: Provides easy content management and backend data tracking for the team.</li>\n<li><strong>DIVI Builder</strong>: Allows modular, flexible design suitable for evolving content needs.</li>\n<li><strong>Custom HTML/CSS/JS</strong>: Tailored dynamic features and streamlined form interactions for a smoother user experience.</li>\n</ul>\n<h4 id=\"results-and-impact\"><strong>Results and Impact</strong></h4>\n<ul>\n<li><strong>Improved Conversion Rate</strong>: Social media-optimized landing page design increased client inquiries and conversions.</li>\n<li><strong>Enhanced Workflow</strong>: Automated “pre-case” initiation system improved intake efficiency and team collaboration.</li>\n<li><strong>Brand Authority</strong>: A professional and functional website establishes Estudio Lena as a leader in personal injury law, providing both credibility and convenience.</li>\n</ul>",{headings:407,localImagePaths:413,remoteImagePaths:414,frontmatter:415,imagePaths:419},[408,409,410,411,412],{depth:37,slug:324,text:325},{depth:41,slug:327,text:328},{depth:41,slug:338,text:339},{depth:41,slug:348,text:349},{depth:41,slug:357,text:358},[],[],{title:395,publishDate:416,img:108,img_alt:399,description:396,tags:417,screenshots:418},["Date","2019-12-01T00:00:00.000Z"],[18,19,20,72],[111,112,113,114,115],[],{id:135,data:421,body:428,filePath:429,digest:430,rendered:431},{title:422,description:423,publishDate:424,tags:425,img:143,img_alt:426,screenshots:427},"Michel Mentalista Website Development","Designed to function as both a portfolio and a conversion-focused landing page!\n",["Date","2020-03-02T00:00:00.000Z"],[212,18,142],"Screenshot of Michel Mentalista website.",[146,147,148,149],"### Project Overview\nThe Michel Mentalista website promotes Michel, a prominent mentalist in Argentina, highlighting his performances across private, corporate, and theater events. Designed to function as both a portfolio and a conversion-focused landing page, it draws audiences through social media funnels to drive inquiries and bookings.\n\n##### Objectives\n- <b>Digital Presence:</b> Elevate Michel’s brand with a modern, memorable site.\n- <b>User engagement and Conversion:</b> Develop a high-converting page optimized for social media traffic.\n- <b>Performance and Accessibility:</b> Ensure fast loading and an accessible, user-friendly interface.\n- <b>Content flexibility:</b> Enable easy updates to the “Shows” and “Gallery” sections to showcase recent events.\n##### Project Workflow\n- <b>Discovery and Planning:</b> Defined the brand with an interactive, visually engaging approach.\n- <b>UX/UI Design:</b> Developed a clear layout with sections like “Shows,” “Trailer,” “Bio,” and “Contact” to improve navigation and engagement.\n- <b>Content strategy:</b> Organized content around Michel’s expertise and testimonials to build credibility.\n- <b>Interactive Elements:</b> Added engaging features like a “Trailer” and a “Gallery” to increase on-page interaction.\n- <b>Testing and Optimization:</b> Conducted speed and usability tests to ensure seamless user experience and effectiveness as a landing page for social media traffic.\n##### Technologies Used\n>WordPress: Chosen for content management to allow ease of updates.\n###\n>DIVI Builder: Used for custom modular design that highlights services and testimonials.\n###\n>Custom HTML/CSS/JS: Integrated interactive elements to enhance UX without impacting loading times.\n\n##### Results and Impact\n- <b>Higher Conversions:</b> The optimized landing page led to increased engagement and bookings.\n- <b>Enhanced Brand Identity:</b> The professional, engaging site establishes Michel as a leading mentalist.\n- <b>Client Empowerment:</b> Michel can now independently manage updates, consistently showcasing his latest work.","src/content/work/Michel.md","a20db6bd3b2e14f0",{html:432,metadata:433},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>The Michel Mentalista website promotes Michel, a prominent mentalist in Argentina, highlighting his performances across private, corporate, and theater events. Designed to function as both a portfolio and a conversion-focused landing page, it draws audiences through social media funnels to drive inquiries and bookings.</p>\n<h5 id=\"objectives\">Objectives</h5>\n<ul>\n<li><b>Digital Presence:</b> Elevate Michel’s brand with a modern, memorable site.</li>\n<li><b>User engagement and Conversion:</b> Develop a high-converting page optimized for social media traffic.</li>\n<li><b>Performance and Accessibility:</b> Ensure fast loading and an accessible, user-friendly interface.</li>\n<li><b>Content flexibility:</b> Enable easy updates to the “Shows” and “Gallery” sections to showcase recent events.</li>\n</ul>\n<h5 id=\"project-workflow\">Project Workflow</h5>\n<ul>\n<li><b>Discovery and Planning:</b> Defined the brand with an interactive, visually engaging approach.</li>\n<li><b>UX/UI Design:</b> Developed a clear layout with sections like “Shows,” “Trailer,” “Bio,” and “Contact” to improve navigation and engagement.</li>\n<li><b>Content strategy:</b> Organized content around Michel’s expertise and testimonials to build credibility.</li>\n<li><b>Interactive Elements:</b> Added engaging features like a “Trailer” and a “Gallery” to increase on-page interaction.</li>\n<li><b>Testing and Optimization:</b> Conducted speed and usability tests to ensure seamless user experience and effectiveness as a landing page for social media traffic.</li>\n</ul>\n<h5 id=\"technologies-used\">Technologies Used</h5>\n<blockquote>\n<p>WordPress: Chosen for content management to allow ease of updates.</p>\n</blockquote>\n<h3 id=\"\"></h3>\n<blockquote>\n<p>DIVI Builder: Used for custom modular design that highlights services and testimonials.</p>\n</blockquote>\n<h3 id=\"-1\"></h3>\n<blockquote>\n<p>Custom HTML/CSS/JS: Integrated interactive elements to enhance UX without impacting loading times.</p>\n</blockquote>\n<h5 id=\"results-and-impact\">Results and Impact</h5>\n<ul>\n<li><b>Higher Conversions:</b> The optimized landing page led to increased engagement and bookings.</li>\n<li><b>Enhanced Brand Identity:</b> The professional, engaging site establishes Michel as a leading mentalist.</li>\n<li><b>Client Empowerment:</b> Michel can now independently manage updates, consistently showcasing his latest work.</li>\n</ul>",{headings:434,localImagePaths:442,remoteImagePaths:443,frontmatter:444,imagePaths:448},[435,436,437,438,439,440,441],{depth:37,slug:324,text:325},{depth:159,slug:327,text:328},{depth:159,slug:338,text:339},{depth:159,slug:348,text:349},{depth:37,slug:330,text:330},{depth:37,slug:332,text:330},{depth:159,slug:357,text:358},[],[],{title:422,publishDate:445,img:143,img_alt:426,description:423,tags:446,screenshots:447},["Date","2020-03-02T00:00:00.000Z"],[212,18,142],[146,147,148,149],[],{id:170,data:450,body:457,filePath:458,digest:459,rendered:460},{title:451,description:452,publishDate:453,tags:454,img:177,img_alt:455,screenshots:456},"Rodrigo Camino Portfolio Website","This article describes my portfolio website, built to showcase my web development and creative skills. Using Astro, Tailwind CSS, HTML, and JavaScript, the site focuses on fast performance, easy updates, and engaging design to enhance my brand and keep content current.\n",["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],"Screenshot of Rodrigo Camino's portfolio",[180,181,182,183,184,185],"### Project Overview\nThis portfolio site serves as my professional showcase, merging my skills in web development and my creative side as a magician based in Buenos Aires. It’s crafted to highlight both my technical expertise and my strategic, imaginative approach through interactive elements and a visually engaging design.\n\n### Objectives\n- **Digital Presence**: Establish a polished, modern site that reflects my technical and creative strengths.\n- **User Engagement**: Provide an interactive experience that showcases my projects effectively.\n- **Performance**: Achieve a fast-loading, optimized site by leveraging Astro and Tailwind CSS.\n- **Maintainability**: Ensure I can easily update the site with new projects and content as they develop.\n\n### Project Workflow\n- **Planning & Discovery**: Focused on defining my brand, ensuring that user flow was both inviting and practical.\n- **Design & Development**:\n  - **UI/UX Design**: Built a minimalist, clean design with intuitive navigation.\n  - **Component-Driven Structure**: Used Astro and Tailwind CSS to create modular components, enhancing load times and responsiveness.\n- **Content Structuring**: Organized sections such as “About,” “Work,” and “Contact” to display expertise and projects efficiently.\n- **Testing & Optimization**: Conducted performance testing, ensuring smooth loading and cross-device compatibility.\n\n### Technologies Used\n- **Astro**: Used to create a static site with excellent performance.\n- **Tailwind CSS**: Enabled rapid, flexible styling adjustments.\n- **HTML & JavaScript**: Integrated for dynamic elements, enhancing interactivity without slowing performance.\n\n### Results and Impact\n- **Enhanced Brand Image**: Created a professional, sleek design that highlights my unique blend of technical and creative skills.\n- **Increased Engagement**: The interactive layout encourages visitors to explore my projects and skills, increasing engagement.\n- **Client Empowerment**: With an easily maintainable structure, I can keep my site up to date and reflective of my latest work.","src/content/work/Portfolio.md","449bc70e60c1b914",{html:461,metadata:462},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>This portfolio site serves as my professional showcase, merging my skills in web development and my creative side as a magician based in Buenos Aires. It’s crafted to highlight both my technical expertise and my strategic, imaginative approach through interactive elements and a visually engaging design.</p>\n<h3 id=\"objectives\">Objectives</h3>\n<ul>\n<li><strong>Digital Presence</strong>: Establish a polished, modern site that reflects my technical and creative strengths.</li>\n<li><strong>User Engagement</strong>: Provide an interactive experience that showcases my projects effectively.</li>\n<li><strong>Performance</strong>: Achieve a fast-loading, optimized site by leveraging Astro and Tailwind CSS.</li>\n<li><strong>Maintainability</strong>: Ensure I can easily update the site with new projects and content as they develop.</li>\n</ul>\n<h3 id=\"project-workflow\">Project Workflow</h3>\n<ul>\n<li><strong>Planning &#x26; Discovery</strong>: Focused on defining my brand, ensuring that user flow was both inviting and practical.</li>\n<li><strong>Design &#x26; Development</strong>:\n<ul>\n<li><strong>UI/UX Design</strong>: Built a minimalist, clean design with intuitive navigation.</li>\n<li><strong>Component-Driven Structure</strong>: Used Astro and Tailwind CSS to create modular components, enhancing load times and responsiveness.</li>\n</ul>\n</li>\n<li><strong>Content Structuring</strong>: Organized sections such as “About,” “Work,” and “Contact” to display expertise and projects efficiently.</li>\n<li><strong>Testing &#x26; Optimization</strong>: Conducted performance testing, ensuring smooth loading and cross-device compatibility.</li>\n</ul>\n<h3 id=\"technologies-used\">Technologies Used</h3>\n<ul>\n<li><strong>Astro</strong>: Used to create a static site with excellent performance.</li>\n<li><strong>Tailwind CSS</strong>: Enabled rapid, flexible styling adjustments.</li>\n<li><strong>HTML &#x26; JavaScript</strong>: Integrated for dynamic elements, enhancing interactivity without slowing performance.</li>\n</ul>\n<h3 id=\"results-and-impact\">Results and Impact</h3>\n<ul>\n<li><strong>Enhanced Brand Image</strong>: Created a professional, sleek design that highlights my unique blend of technical and creative skills.</li>\n<li><strong>Increased Engagement</strong>: The interactive layout encourages visitors to explore my projects and skills, increasing engagement.</li>\n<li><strong>Client Empowerment</strong>: With an easily maintainable structure, I can keep my site up to date and reflective of my latest work.</li>\n</ul>",{headings:463,localImagePaths:469,remoteImagePaths:470,frontmatter:471,imagePaths:475},[464,465,466,467,468],{depth:37,slug:324,text:325},{depth:37,slug:327,text:328},{depth:37,slug:338,text:339},{depth:37,slug:348,text:349},{depth:37,slug:357,text:358},[],[],{title:451,publishDate:472,img:177,img_alt:455,description:452,tags:473,screenshots:474},["Date","2024-10-29T00:00:00.000Z"],[18,19,20,72],[180,181,182,183,184,185],[],{id:205,data:477,body:484,filePath:485,digest:486,rendered:487},{title:478,description:479,publishDate:480,tags:481,img:213,img_alt:482,screenshots:483},"Roberto Mansilla’s Mentalist Website Redesign","Roberto Mansilla, a distinguished mentalist from Argentina, required a website that both spotlights his unique shows and serves as a high-conversion landing page for social media traffic.\n",["Date","2020-03-02T00:00:00.000Z"],[212,18,142],"Screenshot of Roberto Mansilla's website.",[216,217,218,219],"### **Project Overview**\nRoberto Mansilla, a distinguished mentalist from Argentina, required a website that both spotlights his unique shows and serves as a high-conversion landing page for social media traffic. The design features immersive “plate”-style navigation with engaging animations that capture the essence of his performance style and draw users in for bookings.\n\n### **Objectives**\n- **Brand Authority**: Position Roberto as a leading mentalist through a visually memorable site.\n- **User Engagement Funnel**: Smoothly transition visitors from social media to the website, focusing on booking conversion.\n- **Interactive UX Design**: Integrate animations and visual effects to enhance the experience and reflect the mystique of Roberto’s performances.\n- **Self-Management Capability**: Empower Roberto to independently update shows, testimonials, and other dynamic content.\n\n### **Project Workflow**\n1. **Discovery & Strategy**: Established Roberto’s digital brand with a unique layout that reinforces his charismatic stage presence.\n2. **UI/UX Design**: Designed an interactive interface with “plate” navigation for shows, testimonials, and a video trailer, creating an immersive journey for users.\n3. **Content Strategy**: Organized content to highlight core show categories and audience testimonials for credibility.\n4. **Interactive Elements**: Incorporated JavaScript animations that bring an air of intrigue, enhancing engagement while maintaining site performance.\n5. **Testing & Optimization**: Optimized for SEO and streamlined load times to ensure the site functions effectively as a conversion-focused landing page.\n\n### **Technologies Used**\n- **WordPress**: Selected for flexible, user-friendly content management.\n- **DIVI Builder**: Enabled a modular design suited to showcasing Roberto’s services.\n- **HTML/CSS/JS**: Crafted animations for an engaging UX without affecting load times.\n\n### **Results and Impact**\n- **Higher Engagement and Conversion**: The structured landing page boosts bookings from social media sources.\n- **Improved Brand Presence**: A polished, dynamic design establishes Roberto’s authority in the mentalist field.\n- **Ease of Management**: Roberto can now independently manage content, keeping his site fresh with recent shows and testimonials.","src/content/work/RobertoMansilla.md","b62c218ed114e02a",{html:488,metadata:489},"<h3 id=\"project-overview\"><strong>Project Overview</strong></h3>\n<p>Roberto Mansilla, a distinguished mentalist from Argentina, required a website that both spotlights his unique shows and serves as a high-conversion landing page for social media traffic. The design features immersive “plate”-style navigation with engaging animations that capture the essence of his performance style and draw users in for bookings.</p>\n<h3 id=\"objectives\"><strong>Objectives</strong></h3>\n<ul>\n<li><strong>Brand Authority</strong>: Position Roberto as a leading mentalist through a visually memorable site.</li>\n<li><strong>User Engagement Funnel</strong>: Smoothly transition visitors from social media to the website, focusing on booking conversion.</li>\n<li><strong>Interactive UX Design</strong>: Integrate animations and visual effects to enhance the experience and reflect the mystique of Roberto’s performances.</li>\n<li><strong>Self-Management Capability</strong>: Empower Roberto to independently update shows, testimonials, and other dynamic content.</li>\n</ul>\n<h3 id=\"project-workflow\"><strong>Project Workflow</strong></h3>\n<ol>\n<li><strong>Discovery &#x26; Strategy</strong>: Established Roberto’s digital brand with a unique layout that reinforces his charismatic stage presence.</li>\n<li><strong>UI/UX Design</strong>: Designed an interactive interface with “plate” navigation for shows, testimonials, and a video trailer, creating an immersive journey for users.</li>\n<li><strong>Content Strategy</strong>: Organized content to highlight core show categories and audience testimonials for credibility.</li>\n<li><strong>Interactive Elements</strong>: Incorporated JavaScript animations that bring an air of intrigue, enhancing engagement while maintaining site performance.</li>\n<li><strong>Testing &#x26; Optimization</strong>: Optimized for SEO and streamlined load times to ensure the site functions effectively as a conversion-focused landing page.</li>\n</ol>\n<h3 id=\"technologies-used\"><strong>Technologies Used</strong></h3>\n<ul>\n<li><strong>WordPress</strong>: Selected for flexible, user-friendly content management.</li>\n<li><strong>DIVI Builder</strong>: Enabled a modular design suited to showcasing Roberto’s services.</li>\n<li><strong>HTML/CSS/JS</strong>: Crafted animations for an engaging UX without affecting load times.</li>\n</ul>\n<h3 id=\"results-and-impact\"><strong>Results and Impact</strong></h3>\n<ul>\n<li><strong>Higher Engagement and Conversion</strong>: The structured landing page boosts bookings from social media sources.</li>\n<li><strong>Improved Brand Presence</strong>: A polished, dynamic design establishes Roberto’s authority in the mentalist field.</li>\n<li><strong>Ease of Management</strong>: Roberto can now independently manage content, keeping his site fresh with recent shows and testimonials.</li>\n</ul>",{headings:490,localImagePaths:496,remoteImagePaths:497,frontmatter:498,imagePaths:502},[491,492,493,494,495],{depth:37,slug:324,text:325},{depth:37,slug:327,text:328},{depth:37,slug:338,text:339},{depth:37,slug:348,text:349},{depth:37,slug:357,text:358},[],[],{title:478,publishDate:499,img:213,img_alt:482,description:479,tags:500,screenshots:501},["Date","2020-03-02T00:00:00.000Z"],[212,18,142],[216,217,218,219],[],{id:239,data:504,body:510,filePath:511,digest:512,rendered:513},{title:505,description:423,publishDate:506,tags:507,img:246,img_alt:508,screenshots:509,video:255},"Santiago Ilusionista Website",["Date","2020-03-02T00:00:00.000Z"],[212,18,142],"Screenshot of Santiago Ilusionista website.",[249,250,251,252,253,254],"### Project Overview\nThe Santiago Fernández website is a dynamic landing page crafted to showcase Santiago, a leading magician, and draw audiences for various events—corporate, private, and theater. Built as a high-conversion platform, the site leverages social media funnels to engage visitors and drive booking inquiries.\n\n#### Objectives\n- **Digital Presence**: Position Santiago as a top-tier magician across Argentina and Spain.\n- **Conversion Optimization**: Build a landing page optimized to convert social media traffic, boosting event bookings.\n- **Performance & Accessibility**: Ensure fast load times and an accessible, user-friendly interface.\n- **Content Flexibility**: Allow Santiago to easily update recent events and testimonials to stay current with his performances.\n\n#### Project Workflow\n- **Discovery & Planning**: Established a brand-centric site with a modern, interactive design approach.\n- **UX/UI Design**: Structured content in clear sections for services, galleries, and testimonials to build visitor trust and engagement.\n- **Content Strategy**: Focused on Santiago’s unique expertise and real-life client feedback to captivate and convert site visitors.\n- **Interactive Elements**: Integrated a media gallery, various event categories, and social media features for higher engagement.\n- **Testing & Optimization**: Ran usability and speed tests to ensure optimal performance as a social media landing page.\n\n#### Technologies Used\n- **WordPress**: For efficient content management and easy updates.\n- **DIVI Builder**: Enabled a modular design and customizable layout for enhanced engagement.\n- **HTML/CSS/JavaScript**: Applied custom code for interactive elements, minimizing plugin load for better performance.\n\n#### Results and Impact\n- **Increased Bookings**: The optimized landing page effectively drives engagement, converting social media visitors into clients.\n- **Strengthened Brand Authority**: The polished, professional site reinforces Santiago’s position as a leading magician.\n- **Empowered Client**: Santiago can independently update his site to reflect recent events and add testimonials, keeping user interest high.","src/content/work/Santiago.md","d31a9bcfcfb272da",{html:514,metadata:515},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>The Santiago Fernández website is a dynamic landing page crafted to showcase Santiago, a leading magician, and draw audiences for various events—corporate, private, and theater. Built as a high-conversion platform, the site leverages social media funnels to engage visitors and drive booking inquiries.</p>\n<h4 id=\"objectives\">Objectives</h4>\n<ul>\n<li><strong>Digital Presence</strong>: Position Santiago as a top-tier magician across Argentina and Spain.</li>\n<li><strong>Conversion Optimization</strong>: Build a landing page optimized to convert social media traffic, boosting event bookings.</li>\n<li><strong>Performance &#x26; Accessibility</strong>: Ensure fast load times and an accessible, user-friendly interface.</li>\n<li><strong>Content Flexibility</strong>: Allow Santiago to easily update recent events and testimonials to stay current with his performances.</li>\n</ul>\n<h4 id=\"project-workflow\">Project Workflow</h4>\n<ul>\n<li><strong>Discovery &#x26; Planning</strong>: Established a brand-centric site with a modern, interactive design approach.</li>\n<li><strong>UX/UI Design</strong>: Structured content in clear sections for services, galleries, and testimonials to build visitor trust and engagement.</li>\n<li><strong>Content Strategy</strong>: Focused on Santiago’s unique expertise and real-life client feedback to captivate and convert site visitors.</li>\n<li><strong>Interactive Elements</strong>: Integrated a media gallery, various event categories, and social media features for higher engagement.</li>\n<li><strong>Testing &#x26; Optimization</strong>: Ran usability and speed tests to ensure optimal performance as a social media landing page.</li>\n</ul>\n<h4 id=\"technologies-used\">Technologies Used</h4>\n<ul>\n<li><strong>WordPress</strong>: For efficient content management and easy updates.</li>\n<li><strong>DIVI Builder</strong>: Enabled a modular design and customizable layout for enhanced engagement.</li>\n<li><strong>HTML/CSS/JavaScript</strong>: Applied custom code for interactive elements, minimizing plugin load for better performance.</li>\n</ul>\n<h4 id=\"results-and-impact\">Results and Impact</h4>\n<ul>\n<li><strong>Increased Bookings</strong>: The optimized landing page effectively drives engagement, converting social media visitors into clients.</li>\n<li><strong>Strengthened Brand Authority</strong>: The polished, professional site reinforces Santiago’s position as a leading magician.</li>\n<li><strong>Empowered Client</strong>: Santiago can independently update his site to reflect recent events and add testimonials, keeping user interest high.</li>\n</ul>",{headings:516,localImagePaths:522,remoteImagePaths:523,frontmatter:524,imagePaths:528},[517,518,519,520,521],{depth:37,slug:324,text:325},{depth:41,slug:327,text:328},{depth:41,slug:338,text:339},{depth:41,slug:348,text:349},{depth:41,slug:357,text:358},[],[],{title:505,publishDate:525,img:246,img_alt:508,description:423,tags:526,screenshots:527,video:255},["Date","2020-03-02T00:00:00.000Z"],[212,18,142],[249,250,251,252,253,254],[],{id:275,data:530,body:536,filePath:537,digest:538,rendered:539},{title:531,description:532,publishDate:533,tags:534,img:282,img_alt:372,screenshots:535},"Sujetos del Inconsciente Website & Blog","The Sujetos del Inconsciente website, serves as an educational psychology platform focusing on mental health and psychoanalysis.\n",["Date","2019-10-02T00:00:00.000Z"],[212,19,20,72],[285,286,287],"### Project Overview\n This site offers articles, insights, and resources for users interested in exploring psychological and philosophical themes, establishing an inviting space for learning and reflection.\n\n#### Objectives\n- <b>Digital Presence:</b> Strengthen authority in mental health and psychoanalysis.\n\n- <b>Engagement:</b> Foster interaction through a structured blog format.\n\n- <b>SEO & Accessibility:</b> Enhance organic reach and accessibility for diverse users.\n\n- <b>User-friendly CMS:</b> Enable easy updates and content management.\n\n##### Project Workflow\n\n- <b>Planning:</b> Established a clear brand identity and content strategy, focusing on psychoanalytic themes.\n\n- <b>Design & UX:</b> Developed a clean, intuitive layout with clear sections, like \"About,\" \"Blog,\" and \"Contact,\" for seamless navigation.\n\n- <b>Content Strategy:</b> Organized article structures around central psychoanalytic themes such as identity, self-esteem, and educational philosophy.\n\n- <b>Dynamic Features:</b> Incorporated social media links to foster community engagement and sharing.\n\n- <b>Testing:</b> Conducted performance evaluations to optimize accessibility and user experience.\n\n##### Technologies Used\n><b>WordPress:</b> For efficient content management and easy client updates.\n###\n><b>DIVI Builder:</b> Enabled flexible, modular design customization.\n###\n><b>Custom Code (HTML/CSS/JS):</b> Added unique UI/UX elements for a cohesive and professional user experience.\n\n##### Results and Impact\n- <b>Increased Engagement:</b> The structured blog and interactive features facilitate user engagement and participation.\n\n- <b>Enhanced Brand Identity:</b> Created an accessible platform that establishes the client as a trusted voice in mental health.\n\n- <b>User Empowerment:</b> The client can now manage content updates autonomously, enabling consistent engagement and a sustainable online presence.","src/content/work/SDI.md","a6c1689227e14588",{html:540,metadata:541},"<h3 id=\"project-overview\">Project Overview</h3>\n<p>This site offers articles, insights, and resources for users interested in exploring psychological and philosophical themes, establishing an inviting space for learning and reflection.</p>\n<h4 id=\"objectives\">Objectives</h4>\n<ul>\n<li>\n<p><b>Digital Presence:</b> Strengthen authority in mental health and psychoanalysis.</p>\n</li>\n<li>\n<p><b>Engagement:</b> Foster interaction through a structured blog format.</p>\n</li>\n<li>\n<p><b>SEO &#x26; Accessibility:</b> Enhance organic reach and accessibility for diverse users.</p>\n</li>\n<li>\n<p><b>User-friendly CMS:</b> Enable easy updates and content management.</p>\n</li>\n</ul>\n<h5 id=\"project-workflow\">Project Workflow</h5>\n<ul>\n<li>\n<p><b>Planning:</b> Established a clear brand identity and content strategy, focusing on psychoanalytic themes.</p>\n</li>\n<li>\n<p><b>Design &#x26; UX:</b> Developed a clean, intuitive layout with clear sections, like “About,” “Blog,” and “Contact,” for seamless navigation.</p>\n</li>\n<li>\n<p><b>Content Strategy:</b> Organized article structures around central psychoanalytic themes such as identity, self-esteem, and educational philosophy.</p>\n</li>\n<li>\n<p><b>Dynamic Features:</b> Incorporated social media links to foster community engagement and sharing.</p>\n</li>\n<li>\n<p><b>Testing:</b> Conducted performance evaluations to optimize accessibility and user experience.</p>\n</li>\n</ul>\n<h5 id=\"technologies-used\">Technologies Used</h5>\n<blockquote>\n<p><b>WordPress:</b> For efficient content management and easy client updates.</p>\n</blockquote>\n<h3 id=\"\"></h3>\n<blockquote>\n<p><b>DIVI Builder:</b> Enabled flexible, modular design customization.</p>\n</blockquote>\n<h3 id=\"-1\"></h3>\n<blockquote>\n<p><b>Custom Code (HTML/CSS/JS):</b> Added unique UI/UX elements for a cohesive and professional user experience.</p>\n</blockquote>\n<h5 id=\"results-and-impact\">Results and Impact</h5>\n<ul>\n<li>\n<p><b>Increased Engagement:</b> The structured blog and interactive features facilitate user engagement and participation.</p>\n</li>\n<li>\n<p><b>Enhanced Brand Identity:</b> Created an accessible platform that establishes the client as a trusted voice in mental health.</p>\n</li>\n<li>\n<p><b>User Empowerment:</b> The client can now manage content updates autonomously, enabling consistent engagement and a sustainable online presence.</p>\n</li>\n</ul>",{headings:542,localImagePaths:550,remoteImagePaths:551,frontmatter:552,imagePaths:556},[543,544,545,546,547,548,549],{depth:37,slug:324,text:325},{depth:41,slug:327,text:328},{depth:159,slug:338,text:339},{depth:159,slug:348,text:349},{depth:37,slug:330,text:330},{depth:37,slug:332,text:330},{depth:159,slug:357,text:358},[],[],{title:531,publishDate:553,img:282,img_alt:372,description:532,tags:554,screenshots:555},["Date","2019-10-02T00:00:00.000Z"],[212,19,20,72],[285,286,287],[]];

